  1→import { Message } from '@/types';
  2→import { cn } from '@/lib/utils';
  3→import { extractSingleLinePreview, getEventLabel, isToolCallStep } from '@/lib/chatUtils';
  4→import { AlertTriangle, ChevronRight, TerminalSquare, Wrench } from 'lucide-react';
  5→import { MarkdownRenderer } from '@/components/MarkdownRenderer';
  6→import { AskUserFormCard } from '@/components/RequirementCard';
  7→import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from '@/components/ui/tooltip';
  8→import { ThinkingText } from './ThinkingText';
  9→import {
 10→  EVENT_AGENT_START,
 11→  EVENT_INTERRUPT,
 12→  EVENT_CONTEXT_SUMMARIZED,
 13→  EVENT_ERROR,
 14→  EVENT_TOOL_OUTPUT,
 15→} from '@/lib/const';
 16→
 17→function getDetailStatus(message: Message): string | undefined {
 18→  return message.toolDetail?.summary.split(' · ').at(-1);
 19→}
 20→
 21→function shouldHideCompletedStatus(message: Message): boolean {
 22→  return getDetailStatus(message) === '已完成';
 23→}
 24→
 25→function getOutputLengthBadgeClass(outputLength?: number): string {
 26→  if (typeof outputLength !== 'number') {
 27→    return 'bg-muted text-muted-foreground/70';
 28→  }
 29→
 30→  if (outputLength >= 5000) {
 31→    return 'bg-red-100/80 text-red-600 dark:bg-red-900/40 dark:text-red-400';
 32→  }
 33→
 34→  if (outputLength >= 2000) {
 35→    return 'bg-amber-100/80 text-amber-600 dark:bg-amber-900/40 dark:text-amber-400';
 36→  }
 37→
 38→  if (outputLength >= 500) {
 39→    return 'bg-blue-100/80 text-blue-600 dark:bg-blue-900/40 dark:text-blue-400';
 40→  }
 41→
 42→  return 'bg-muted text-muted-foreground/70';
 43→}
 44→
 45→function OutputLengthBadge({
 46→  outputLength,
 47→  isError = false,
 48→  className,
 49→}: {
 50→  outputLength?: number;
 51→  isError?: boolean;
 52→  className?: string;
 53→}) {
 54→  if (typeof outputLength !== 'number') {
 55→    return null;
 56→  }
 57→
 58→  return (
 59→    <span
 60→      className={cn(
 61→        'shrink-0 rounded-md px-1.5 py-[3px] text-[10px] font-medium uppercase tracking-wide',
 62→        isError ? 'bg-destructive/10 text-destructive/80' : getOutputLengthBadgeClass(outputLength),
 63→        className,
 64→      )}
 65→    >
 66→      {outputLength} chars
 67→    </span>
 68→  );
 69→}
