 26→interface MessageListProps {
 27→  messages: Message[];
 28→  isLoading: boolean;
 29→  onAskUserSubmit: (interruptId: string | undefined, values: string | Record<string, unknown>) => Promise<void>;
 30→  scrollRef: React.RefObject<HTMLDivElement>;
 31→  selectedDetailMessageId?: string;
 32→  selectedSubagentKey?: string;
 33→  onSelectToolDetail?: (messageId: string) => void;
 34→  onSelectSubagent?: (subagentKey: string) => void;
