123→const USER_AVATAR_CLASSNAME =
124→  'absolute right-0 top-0 h-8 w-8 border bg-primary text-primary-foreground shadow-sm';
125→
126→const ASSISTANT_AVATAR_CLASSNAME =
127→  'absolute left-0 top-0 h-8 w-8 border bg-muted shadow-sm';
