129→function getThinkingSummary(messages: Message[]): string {
130→  for (let index = messages.length - 1; index >= 0; index -= 1) {
131→    const message = messages[index];
132→    if (!message) continue;
133→
134→    if (typeof message.thinking === 'string') {
135→      const thinkingPreview = extractSingleLinePreview(message.thinking, 36);
136→      if (thinkingPreview) return thinkingPreview;
137→    }
138→
139→    if (message.event === EVENT_ASSISTANT) {
140→      const assistantPreview = extractSingleLinePreview(message.content, 36);
141→      if (assistantPreview) return assistantPreview;
142→    }
143→
144→    if (isToolCallStep(message.event)) {
145→      return `调用工具: ${message.toolName || 'tool'}`;
146→    }
147→
148→    if (message.event === EVENT_TOOL_OUTPUT) {
149→      return `收到工具结果: ${message.toolName || 'tool'}`;
150→    }
151→  }
152→
153→  return '思考中...';
154→}
155→
156→function getMessageSource(message: Message): StreamSource {
157→  return message.source || { kind: 'main', key: 'main', label: message.node };
158→}
