 43→export const formatEventContent = (event: ChatEvent): string => {
 44→  if (!event.data) return '';
 45→  if (typeof event.data === 'string') return event.data;
 46→  const data = event.data as Record<string, unknown>;
 47→  
 48→  const tryFormatJson = (val: unknown) => {
 49→    if (typeof val === 'string') {
 50→      try {
 51→        const parsed = JSON.parse(val);
 52→        return JSON.stringify(parsed, null, 2);
 53→      } catch {
 54→        return val;
 55→      }
 56→    }
 57→    return JSON.stringify(val, null, 2);
 58→  };
 59→
 60→  if (event.event === EVENT_TOOL_OUTPUT || event.event === EVENT_TOOL_CALL_RESULT) {
 61→    const output = data.error ?? data.output ?? data.result ?? data.content ?? data.text ?? data.message ?? data;
 62→    return tryFormatJson(output);
 63→  }
 64→
 65→  if (event.event === EVENT_TOOL_CALL || event.event === EVENT_TOOL_INPUT) {
 66→    const input = data.input ?? data.args ?? data.content ?? data.text ?? data.message ?? data;
 67→    return tryFormatJson(input);
 68→  }
 69→
 70→  const text = data.content ?? data.text ?? data.message;
 71→  return tryFormatJson(text ?? data);
 72→};
