  1→import { Message } from '@/types';
  2→import {
  3→  EVENT_ASSISTANT,
  4→  EVENT_ERROR,
  5→  EVENT_TOOL_CALL,
  6→  EVENT_TOOL_CALL_RESULT,
  7→  EVENT_TOOL_INPUT,
  8→  EVENT_TOOL_OUTPUT,
  9→} from '@/lib/const';
 10→
 11→export type ToolDisplayItem =
 12→  | { type: 'message'; key: string; message: Message }
 13→  | { type: 'tool-pair'; key: string; primary: Message; secondary: Message };
 14→
 15→export type AssistantDisplayItem =
 16→  | ToolDisplayItem
 17→  | { type: 'thinking-group'; key: string; messages: Message[]; streamingMessageId?: string };
 18→
 19→type AssistantDisplayBuffers = {
 20→  thinkingMessages: Message[];
 21→  normalMessages: Message[];
 22→};
 23→
 24→function isToolPairStart(message: Message) {
 25→  return message.event === EVENT_TOOL_INPUT || message.event === EVENT_TOOL_CALL;
 26→}
 27→
 28→function isToolPairEnd(message: Message) {
 29→  return (
 30→    message.event === EVENT_TOOL_OUTPUT ||
 31→    message.event === EVENT_TOOL_CALL_RESULT ||
 32→    (message.event === EVENT_ERROR && !!message.toolName)
 33→  );
 34→}
 35→
 36→function canMergeToolMessages(current: Message, next: Message) {
 37→  const hasMatchingToolCallId =
 38→    !!current.toolCallId &&
 39→    !!next.toolCallId &&
 40→    current.toolCallId === next.toolCallId;
 41→
 42→  return (
 43→    current.role === 'assistant' &&
 44→    next.role === 'assistant' &&
 45→    (hasMatchingToolCallId ||
 46→      (!!current.toolName &&
 47→        current.toolName === next.toolName &&
 48→        !current.toolCallId &&
 49→        !next.toolCallId)) &&
 50→    isToolPairStart(current) &&
 51→    isToolPairEnd(next)
 52→  );
 53→}
 54→
 55→// tool pair 匹配层：负责把 input/call 与 output/result/error 对齐。
 56→export function findToolPairEndIndex(messages: Message[], startIndex: number, consumedIndexes: Set<number>) {
 57→  const start = messages[startIndex];
 58→  if (!isToolPairStart(start)) return -1;
 59→
 60→  if (start.toolCallId) {
 61→    for (let index = startIndex + 1; index < messages.length; index += 1) {
 62→      if (consumedIndexes.has(index)) continue;
 63→      const candidate = messages[index];
 64→      if (canMergeToolMessages(start, candidate)) {
 65→        return index;
 66→      }
 67→    }
 68→    return -1;
 69→  }
 70→
 71→  const nextIndex = startIndex + 1;
 72→  if (nextIndex < messages.length && !consumedIndexes.has(nextIndex)) {
 73→    const next = messages[nextIndex];
 74→    if (canMergeToolMessages(start, next)) {
 75→      return nextIndex;
 76→    }
 77→  }
 78→
 79→  return -1;
 80→}
 81→
 82→function hasThinking(message: Message) {
 83→  return typeof message.thinking === 'string' && message.thinking.trim().length > 0;
 84→}
 85→
 86→function hasContent(message: Message) {
 87→  return typeof message.content === 'string' && message.content.trim().length > 0;
 88→}
 89→
 90→function shouldFoldIntoThinking(message: Message) {
 91→  return hasThinking(message) || isToolPairStart(message) || isToolPairEnd(message);
 92→}
 93→
 94→function startsNormalRendering(message: Message) {
 95→  return message.event === EVENT_ASSISTANT && hasContent(message);
 96→}
 97→
 98→// assistant 拆分层：同一条消息既有 thinking 又开始输出 content 时，
 99→// UI 需要把它拆成 “折叠思考” 和 “正常回答” 两部分。
100→export function splitAssistantMessageForDisplay(message: Message): { thinkingMessage: Message; contentMessage: Message } {
101→  return {
102→    thinkingMessage: {
103→      ...message,
104→      content: '',
105→    },
106→    contentMessage: {
107→      ...message,
108→      thinking: undefined,
109→    },
110→  };
111→}
112→
113→function createToolDisplayItem(message: Message): ToolDisplayItem {
114→  return {
115→    type: 'message',
116→    key: message.id,
117→    message,
118→  };
119→}
120→
121→function createToolPairItem(primary: Message, secondary: Message): ToolDisplayItem {
122→  return {
123→    type: 'tool-pair',
124→    key: `${primary.id}:${secondary.id}`,
125→    primary,
126→    secondary,
127→  };
128→}
129→
130→function createThinkingGroupItem(
131→  messages: Message[],
132→  index: number,
133→  streamingMessageId?: string,
134→): Extract<AssistantDisplayItem, { type: 'thinking-group' }> {
135→  return {
136→    type: 'thinking-group',
137→    key: `thinking-group-${index}`,
138→    messages,
139→    streamingMessageId:
140→      streamingMessageId && messages.some(message => message.id === streamingMessageId)
141→        ? streamingMessageId
142→        : undefined,
143→  };
144→}
145→
146→function flushThinkingMessages(
147→  items: AssistantDisplayItem[],
148→  buffers: AssistantDisplayBuffers,
149→  streamingMessageId?: string,
150→): void {
151→  if (buffers.thinkingMessages.length === 0) {
152→    return;
153→  }
154→
155→  items.push(createThinkingGroupItem(buffers.thinkingMessages, items.length, streamingMessageId));
156→  buffers.thinkingMessages = [];
157→}
158→
159→function flushNormalMessages(items: AssistantDisplayItem[], buffers: AssistantDisplayBuffers): void {
160→  if (buffers.normalMessages.length === 0) {
161→    return;
162→  }
163→
164→  items.push(...buildToolDisplayItems(buffers.normalMessages));
165→  buffers.normalMessages = [];
166→}
167→
168→export function buildToolDisplayItems(messages: Message[]): ToolDisplayItem[] {
169→  const items: ToolDisplayItem[] = [];
170→  const consumedIndexes = new Set<number>();
171→
172→  for (let index = 0; index < messages.length; index += 1) {
173→    if (consumedIndexes.has(index)) continue;
174→
175→    const current = messages[index];
176→    const matchingEndIndex = findToolPairEndIndex(messages, index, consumedIndexes);
177→
178→    if (matchingEndIndex !== -1) {
179→      const next = messages[matchingEndIndex];
180→      items.push(createToolPairItem(current, next));
181→      consumedIndexes.add(matchingEndIndex);
182→      continue;
183→    }
184→
185→    items.push(createToolDisplayItem(current));
186→  }
187→
188→  return items;
189→}
190→
191→export function buildAssistantDisplayItems(messages: Message[], streamingMessageId?: string): AssistantDisplayItem[] {
192→  const items: AssistantDisplayItem[] = [];
193→  const buffers: AssistantDisplayBuffers = {
194→    thinkingMessages: [],
195→    normalMessages: [],
196→  };
197→  let hasStartedNormalRendering = false;
198→
199→  for (const message of messages) {
200→    const messageHasThinking = hasThinking(message);
201→    const shouldStartNormalRendering = startsNormalRendering(message);
202→
203→    if (!hasStartedNormalRendering && message.event === EVENT_ASSISTANT && messageHasThinking && shouldStartNormalRendering) {
204→      const { thinkingMessage, contentMessage } = splitAssistantMessageForDisplay(message);
205→      flushNormalMessages(items, buffers);
206→      buffers.thinkingMessages.push(thinkingMessage);
207→      flushThinkingMessages(items, buffers, streamingMessageId);
208→      hasStartedNormalRendering = true;
209→      buffers.normalMessages.push(contentMessage);
210→      continue;
211→    }
212→
213→    if (!hasStartedNormalRendering && shouldStartNormalRendering) {
214→      flushThinkingMessages(items, buffers, streamingMessageId);
215→      hasStartedNormalRendering = true;
216→      buffers.normalMessages.push(message);
217→      continue;
218→    }
219→
220→    if (!hasStartedNormalRendering && shouldFoldIntoThinking(message)) {
221→      buffers.thinkingMessages.push(message);
222→      continue;
223→    }
224→
225→    if (!hasStartedNormalRendering) {
226→      flushThinkingMessages(items, buffers, streamingMessageId);
227→      items.push(createToolDisplayItem(message));
228→      continue;
229→    }
230→
231→    buffers.normalMessages.push(message);
232→  }
233→
234→  flushThinkingMessages(items, buffers, streamingMessageId);
235→  flushNormalMessages(items, buffers);
236→  return items;
237→}
