 36→
 37→function SubagentPreviewText({
 38→  text,
 39→  enableTooltip,
 40→  className,
 41→}: {
 42→  text: string;
 43→  enableTooltip: boolean;
 44→  className?: string;
 45→}) {
 46→  const textRef = useRef<HTMLDivElement>(null);
 47→  const [isOverflowing, setIsOverflowing] = useState(false);
 48→
 49→  useEffect(() => {
 50→    if (!enableTooltip) {
 51→      setIsOverflowing(false);
 52→      return;
 53→    }
 54→
 55→    const element = textRef.current;
 56→    if (!element) {
 57→      return;
 58→    }
 59→
 60→    const checkOverflow = () => {
 61→      setIsOverflowing(element.scrollWidth > element.clientWidth);
 62→    };
 63→
 64→    checkOverflow();
 65→
 66→    if (typeof ResizeObserver !== 'undefined') {
 67→      const observer = new ResizeObserver(checkOverflow);
 68→      observer.observe(element);
 69→      return () => observer.disconnect();
 70→    }
 71→
 72→    window.addEventListener('resize', checkOverflow);
 73→    return () => window.removeEventListener('resize', checkOverflow);
 74→  }, [enableTooltip, text]);
 75→
 76→  const content = (
 77→    <div ref={textRef} className={className}>
 78→      {text}
 79→    </div>
 80→  );
 81→
 82→  if (!enableTooltip || !isOverflowing) {
 83→    return content;
 84→  }
 85→
 86→  return (
 87→    <TooltipProvider delayDuration={150}>
 88→      <Tooltip>
 89→        <TooltipTrigger asChild>{content}</TooltipTrigger>
 90→        <TooltipContent side="top" align="start" className="max-w-sm p-3">
 91→          <div className="whitespace-pre-wrap break-words text-xs leading-5">{text}</div>
 92→        </TooltipContent>
 93→      </Tooltip>
 94→    </TooltipProvider>
 95→  );
 96→}
 97→
 98→type MessageBlock =
 99→  | { type: 'user'; message: Message }
100→  | { type: 'assistant'; messages: Message[] };
101→
102→type AssistantContentItem =
103→  | { type: 'main'; key: string; messages: Message[] }
104→  | { type: 'subagent'; key: string; source: StreamSource; messages: Message[] };
105→
106→type AssistantContentView =
107→  | { type: 'main'; key: string; items: AssistantDisplayItem[] }
108→  | {
109→      type: 'subagent';
110→      key: string;
111→      label: string;
112→      preview: string;
113→      taskDescription?: string;
114→      latestAssistantContent?: string;
115→      completed: boolean;
116→      error?: boolean;
117→      isActive: boolean;
118→      todos: TodoItem[];
119→      showTodoPanel: boolean;
120→      items: ToolDisplayItem[];
121→    };
122→
123→const USER_AVATAR_CLASSNAME =
124→  'absolute right-0 top-0 h-8 w-8 border bg-primary text-primary-foreground shadow-sm';
125→
126→const ASSISTANT_AVATAR_CLASSNAME =
127→  'absolute left-0 top-0 h-8 w-8 border bg-muted shadow-sm';
128→
129→function getThinkingSummary(messages: Message[]): string {
130→  for (let index = messages.length - 1; index >= 0; index -= 1) {
131→    const message = messages[index];
132→    if (!message) continue;
133→
134→    if (typeof message.thinking === 'string') {
135→      const thinkingPreview = extractSingleLinePreview(message.thinking, 36);
136→      if (thinkingPreview) return thinkingPreview;
137→    }
138→
139→    if (message.event === EVENT_ASSISTANT) {
140→      const assistantPreview = extractSingleLinePreview(message.content, 36);
141→      if (assistantPreview) return assistantPreview;
142→    }
143→
144→    if (isToolCallStep(message.event)) {
145→      return `调用工具: ${message.toolName || 'tool'}`;
146→    }
147→
148→    if (message.event === EVENT_TOOL_OUTPUT) {
149→      return `收到工具结果: ${message.toolName || 'tool'}`;
150→    }
151→  }
152→
153→  return '思考中...';
154→}
155→
156→function getMessageSource(message: Message): StreamSource {
157→  return message.source || { kind: 'main', key: 'main', label: message.node };
158→}
159→
160→export function getAssistantContentRenderKey(contentViewKey: string, itemKey: string): string {
161→  return `${contentViewKey}:${itemKey}`;
162→}
163→
164→function isHiddenSubagentItem(item: ReturnType<typeof buildToolDisplayItems>[number]): boolean {
165→  if (item.type === 'tool-pair') {
166→    return (
167→      item.primary.toolName === 'task' ||
168→      item.secondary.toolName === 'task' ||
169→      item.primary.event === EVENT_TODO_UPDATE ||
170→      item.secondary.event === EVENT_TODO_UPDATE ||
171→      item.primary.event === EVENT_AGENT_END ||
172→      item.secondary.event === EVENT_AGENT_END ||
173→      item.primary.event === EVENT_ASSISTANT_END ||
174→      item.secondary.event === EVENT_ASSISTANT_END
175→    );
176→  }
177→
178→  return (
179→    item.message.toolName === 'task' ||
180→    item.message.event === EVENT_TODO_UPDATE ||
181→    item.message.event === EVENT_AGENT_END ||
182→    item.message.event === EVENT_ASSISTANT_END
183→  );
184→}
185→
186→function buildBlocks(messages: Message[]): MessageBlock[] {
187→  const blocks: MessageBlock[] = [];
188→  let currentAssistantBlock: Message[] = [];
189→
190→  const flushAssistantBlock = () => {
191→    if (currentAssistantBlock.length === 0) return;
192→    blocks.push({ type: 'assistant', messages: currentAssistantBlock });
193→    currentAssistantBlock = [];
194→  };
195→
196→  for (const message of messages) {
197→    if (message.role === 'user') {
198→      flushAssistantBlock();
199→      blocks.push({ type: 'user', message });
200→      continue;
201→    }
202→    currentAssistantBlock.push(message);
203→  }
204→
205→  flushAssistantBlock();
206→  return blocks;
207→}
208→
209→function buildAssistantContentItems(messages: Message[]): AssistantContentItem[] {
210→  const items: AssistantContentItem[] = [];
211→  let currentMainMessages: Message[] = [];
212→  const subagentItemsByKey = new Map<string, AssistantContentItem>();
213→
214→  const flushMainMessages = () => {
215→    if (currentMainMessages.length === 0) return;
216→    items.push({
217→      type: 'main',
218→      key: `main-${items.length}`,
219→      messages: currentMainMessages,
220→    });
221→    currentMainMessages = [];
222→  };
223→
224→  for (const message of messages) {
225→    const source = getMessageSource(message);
226→    if (source.kind !== 'subagent') {
227→      currentMainMessages.push(message);
228→      continue;
229→    }
230→
231→    flushMainMessages();
232→    const existing = subagentItemsByKey.get(source.key);
233→    if (existing && existing.type === 'subagent') {
234→      existing.messages.push(message);
235→      continue;
236→    }
237→
238→    const item: AssistantContentItem = {
239→      type: 'subagent',
240→      key: source.key,
241→      source,
242→      messages: [message],
243→    };
244→    subagentItemsByKey.set(source.key, item);
245→    items.push(item);
246→  }
247→
248→  flushMainMessages();
249→  return items;
250→}
251→
252→// 先把原始消息整理成”主 assistant 内容 / subagent 卡片”两类视图模型，
253→// 渲染层只消费这个中间结构，避免 JSX 里反复推导状态。
254→function buildAssistantContentViews(
255→  messages: Message[],
256→  streamingMessageId?: string,
257→  activeMessageId?: string,
258→) {
259→  const contentItems = buildAssistantContentItems(messages);
260→  const contentViews = contentItems.map<AssistantContentView>(contentItem => {
261→    if (contentItem.type === 'subagent') {
262→      const displayState = buildSubagentDisplayState({
263→        key: contentItem.key,
264→        label: contentItem.source.label || 'Subagent',
265→        messages: contentItem.messages,
266→      });
267→
268→      // A subagent is active if the last overall assistant message belongs to it
269→      const isActive = Boolean(
270→        activeMessageId && contentItem.messages.some(message => message.id === activeMessageId),
271→      );
272→
273→      return {
274→        type: 'subagent',
275→        key: displayState.key,
276→        label: displayState.label,
277→        preview: displayState.preview,
278→        taskDescription: displayState.taskDescription,
279→        latestAssistantContent: displayState.latestAssistantContent,
280→        completed: displayState.completed,
281→        error: displayState.error,
282→        isActive,
283→        todos: displayState.todos,
284→        showTodoPanel: displayState.showTodoPanel,
285→        items: buildToolDisplayItems(contentItem.messages).filter(item => !isHiddenSubagentItem(item)),
286→      };
287→    }
288→
289→    return {
290→      type: 'main',
291→      key: contentItem.key,
292→      items: buildAssistantDisplayItems(contentItem.messages, streamingMessageId),
293→    };
294→  });
295→
296→  return contentViews;
297→}
