299→interface MessageRenderCallbacks {
300→  isLoading: boolean;
301→  selectedDetailMessageId?: string;
302→  selectedSubagentKey?: string;
303→  onAskUserSubmit: (interruptId: string | undefined, values: string | Record<string, unknown>) => Promise<void>;
304→  onSelectToolDetail?: (messageId: string) => void;
305→  onSelectSubagent?: (subagentKey: string) => void;
306→}
307→
308→function renderToolDisplayItem(
309→  item: ToolDisplayItem,
310→  streamingMessageId: string | undefined,
311→  callbacks: MessageRenderCallbacks,
312→  options?: { displayVariant?: 'default' | 'thinking'; thinkingDisplayMode?: 'collapsible' | 'inline' },
313→) {
314→  if (item.type === 'tool-pair') {
315→    return (
316→      <MessageItem
317→        key={item.key}
318→        message={item.primary}
319→        secondaryMessage={item.secondary}
320→        isLoading={callbacks.isLoading}
321→        isStreaming={item.primary.id === streamingMessageId || item.secondary.id === streamingMessageId}
322→        displayVariant={options?.displayVariant}
323→        thinkingDisplayMode={options?.thinkingDisplayMode}
324→        isSelected={item.primary.id === callbacks.selectedDetailMessageId}
325→        onAskUserSubmit={callbacks.onAskUserSubmit}
326→        onSelectToolDetail={callbacks.onSelectToolDetail}
327→      />
328→    );
329→  }
330→
331→  return (
332→    <MessageItem
333→      key={item.key}
334→      message={item.message}
335→      isLoading={callbacks.isLoading}
336→      isStreaming={item.message.id === streamingMessageId}
337→      displayVariant={options?.displayVariant}
338→      thinkingDisplayMode={options?.thinkingDisplayMode}
339→      isSelected={item.message.id === callbacks.selectedDetailMessageId}
340→      onAskUserSubmit={callbacks.onAskUserSubmit}
341→      onSelectToolDetail={callbacks.onSelectToolDetail}
342→    />
343→  );
344→}
345→
346→function renderThinkingGroup(
347→  item: Extract<AssistantDisplayItem, { type: 'thinking-group' }>,
348→  callbacks: MessageRenderCallbacks,
349→) {
350→  const thinkingGroupStreamingId = item.streamingMessageId;
351→  const summaryPreview = getThinkingSummary(item.messages);
352→
353→  return (
354→    <details
355→      key={item.key}
356→      className="group min-w-0 overflow-hidden rounded-lg border border-border/70 bg-muted/30 px-3 py-2"
357→    >
358→      <summary className="flex cursor-pointer list-none items-center gap-1.5 text-xs font-medium text-muted-foreground [&::-webkit-details-marker]:hidden">
359→        <ChevronRight className="h-3.5 w-3.5 shrink-0 transition-transform duration-200 group-open:rotate-90" />
360→        <span
361→          className={cn(
362→            'group-open:hidden truncate',
363→            thinkingGroupStreamingId && 'animate-pulse',
364→          )}
365→        >
366→          {summaryPreview}
367→        </span>
368→        <span className="hidden group-open:inline">思考过程</span>
369→      </summary>
370→      <div className="mt-2 min-w-0 space-y-2 overflow-hidden">
371→        {buildToolDisplayItems(item.messages).map(thinkingItem => {
372→          if (thinkingItem.type === 'tool-pair') {
373→            return renderToolDisplayItem(thinkingItem, thinkingGroupStreamingId, callbacks, {
374→              displayVariant: 'thinking',
375→            });
376→          }
377→
378→          const isSingleToolMessage =
379→            isToolCallStep(thinkingItem.message.event) ||
380→            thinkingItem.message.event === EVENT_TOOL_OUTPUT;
381→
382→          if (isSingleToolMessage) {
383→            return renderToolDisplayItem(thinkingItem, thinkingGroupStreamingId, callbacks, {
384→              displayVariant: 'thinking',
385→            });
386→          }
387→
388→          const thinkingText = thinkingItem.message.thinking || thinkingItem.message.content;
389→          if (thinkingText) {
390→            return (
391→              <div
392→                key={`thinking-${thinkingItem.key}`}
393→                className="min-w-0 overflow-hidden text-muted-foreground/75"
394→              >
395→                <ThinkingText content={thinkingText} />
396→              </div>
397→            );
398→          }
399→
400→          return renderToolDisplayItem(thinkingItem, thinkingGroupStreamingId, callbacks, {
401→            displayVariant: 'thinking',
402→          });
403→        })}
404→      </div>
405→    </details>
406→  );
407→}
408→
409→function renderMainContentView(
410→  contentView: Extract<AssistantContentView, { type: 'main' }>,
411→  streamingMessageId: string | undefined,
412→  callbacks: MessageRenderCallbacks,
413→) {
414→  return contentView.items.map(item => {
415→    const renderKey = getAssistantContentRenderKey(contentView.key, item.key);
416→
417→    if (item.type === 'thinking-group') {
418→      return (
419→        <Fragment key={renderKey}>
420→          {renderThinkingGroup(item, callbacks)}
421→        </Fragment>
422→      );
423→    }
424→
425→    if (item.type === 'tool-pair') {
426→      return (
427→        <Fragment key={renderKey}>
428→          <MessageItem
429→            key={item.key}
430→            message={item.primary}
431→            secondaryMessage={item.secondary}
432→            isLoading={callbacks.isLoading}
433→            isStreaming={item.secondary.id === streamingMessageId}
434→            isSelected={item.primary.id === callbacks.selectedDetailMessageId}
435→            onAskUserSubmit={callbacks.onAskUserSubmit}
436→            onSelectToolDetail={callbacks.onSelectToolDetail}
437→          />
438→        </Fragment>
439→      );
440→    }
441→
442→    return (
443→      <Fragment key={renderKey}>
444→        <MessageItem
445→          key={item.key}
446→          message={item.message}
447→          isLoading={callbacks.isLoading}
448→          isStreaming={item.message.id === streamingMessageId && item.message.event !== EVENT_TOOL_INPUT}
449→          isSelected={item.message.id === callbacks.selectedDetailMessageId}
450→          onAskUserSubmit={callbacks.onAskUserSubmit}
451→          onSelectToolDetail={callbacks.onSelectToolDetail}
452→        />
453→      </Fragment>
454→    );
455→  });
456→}
457→
458→function renderTodoStatusIcon(status: TodoItem['status']) {
459→  if (status === 'completed') {
460→    return (
461→      <span className="flex h-4 w-4 items-center justify-center rounded-full bg-foreground text-background">
462→        <Check className="h-2.5 w-2.5" strokeWidth={3} />
463→      </span>
464→    );
465→  }
466→
467→  if (status === 'in_progress') {
468→    return <Loader2 className="h-4 w-4 animate-spin text-muted-foreground" />;
469→  }
470→
471→  return <Circle className="h-4 w-4 text-muted-foreground" />;
472→}
473→
474→function renderSubagentTodoList(
475→  keyPrefix: string,
476→  todos: TodoItem[],
477→  contentClassName: string,
478→) {
479→  return (
480→    <ol className="space-y-2">
481→      {todos.map((todo, index) => (
482→        <li key={`${keyPrefix}-${todo.content}-${index}`} className="flex items-start gap-2 text-xs">
483→          <span className="mt-[2px] shrink-0">{renderTodoStatusIcon(todo.status)}</span>
484→          <span className="text-muted-foreground tabular-nums">{index + 1}.</span>
485→          <span
486→            className={cn(
487→              'min-w-0 flex-1 leading-5',
488→              contentClassName,
489→              todo.status === 'completed' && 'text-muted-foreground line-through',
490→            )}
491→          >
492→            {todo.content}
493→          </span>
494→        </li>
495→      ))}
496→    </ol>
497→  );
498→}
499→
500→function renderSubagentContentView(
501→  contentView: Extract<AssistantContentView, { type: 'subagent' }>,
502→  callbacks: MessageRenderCallbacks,
503→) {
504→  const isSelected = callbacks.selectedSubagentKey === contentView.key;
505→  const labelContent = (
506→    <div className="min-w-0 flex-1">
507→      <div className="truncate text-sm font-semibold text-foreground">{contentView.label}</div>
508→      <SubagentPreviewText
509→        text={contentView.preview}
510→        enableTooltip={Boolean(contentView.latestAssistantContent && !contentView.completed)}
511→        className={cn(
512→          'truncate text-xs',
513→          contentView.error ? 'text-destructive' : 'text-muted-foreground',
514→          callbacks.isLoading && contentView.isActive && !contentView.completed && !contentView.error && 'animate-pulse',
515→        )}
516→      />
517→    </div>
518→  );
519→
520→  return (
521→    <button
522→      type="button"
523→      key={`subagent-${contentView.key}`}
524→      data-subagent-card={contentView.key}
525→      aria-pressed={isSelected}
526→      onClick={() => callbacks.onSelectSubagent?.(contentView.key)}
527→      className={cn(
528→        'group/subagent relative flex w-full items-center gap-3 overflow-visible rounded-2xl border px-4 py-3 text-left shadow-sm transition-colors',
529→        contentView.error
530→          ? 'border-destructive/40 bg-destructive/5'
531→          : isSelected
532→            ? 'border-primary/40 bg-primary/5'
533→            : 'border-border/60 bg-muted/20 hover:bg-muted/35',
534→      )}
535→    >
536→      <div className="flex h-8 w-8 shrink-0 items-center justify-center rounded-full border bg-background text-foreground/80 shadow-sm">
537→        <Bot className="h-4 w-4" />
538→      </div>
539→      {labelContent}
540→      <ChevronRight className="h-4 w-4 shrink-0 text-muted-foreground" />
541→
542→      {contentView.showTodoPanel && (
543→        <div className="pointer-events-none absolute left-[calc(100%+0.75rem)] top-0 z-20 w-80 rounded-xl border border-border/70 bg-popover/95 p-3 opacity-0 shadow-xl transition-opacity duration-150 group-hover/subagent:opacity-100">
544→          <div className="mb-2 text-[10px] font-semibold uppercase tracking-[0.16em] text-muted-foreground">
545→            {contentView.label} Todos
546→          </div>
547→          {renderSubagentTodoList(contentView.key, contentView.todos, 'text-popover-foreground')}
548→        </div>
549→      )}
550→    </button>
551→  );
552→}
