import { useEffect, useMemo, useRef, useState } from 'react';
import { Button } from '@/components/ui/button';
import { Textarea } from '@/components/ui/textarea';
import { TodoListBlock } from '@/components/chat/TodoListBlock';
import { DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuTrigger } from '@/components/ui/dropdown-menu';
import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from '@/components/ui/tooltip';
import { Check, ChevronDown, Send } from 'lucide-react';
import type { TodoTreeItem } from '@/types';
import { cn } from '@/lib/utils';
import { type ModelId } from '@/lib/const';
import { getTokenUsagePercent } from '@/lib/tokenUsage';
import { filterSkillNames, findSkillCommand, insertSkillCommand } from './chatInputUtils';

interface ChatInputProps {
  input: string;
  isLoading: boolean;
  todoTree?: TodoTreeItem[];
  skills?: string[];
  availableModels?: ModelId[];
  selectedModel: ModelId;
  onModelChange: (model: ModelId) => void;
  modelSelectionDisabled?: boolean;
  tokenUsage: { used: number; capacity: number };
  onInputChange: (value: string) => void;
  onSend: () => void;
}

export function ChatInput({
  input,
  isLoading,
  todoTree = [],
  skills = [],
  availableModels = [],
  selectedModel,
  onModelChange,
  modelSelectionDisabled = false,
  tokenUsage,
  onInputChange,
  onSend,
}: ChatInputProps) {
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const pendingSelectionRef = useRef<{ start: number; end: number } | undefined>();
  const shouldShowTodoPanel = todoTree.some(
    todo => todo.status !== 'completed' || todo.children.some(group => group.todos.some(item => item.status !== 'completed')),
  );
  const [selection, setSelection] = useState({ start: input.length, end: input.length });
  const [activeSkillIndex, setActiveSkillIndex] = useState(0);
  const [dismissedSkillCommandKey, setDismissedSkillCommandKey] = useState<string | undefined>();
  const modelCandidates = useMemo(() => {
    if (availableModels.length === 0) {
      return [selectedModel];
    }
    if (availableModels.includes(selectedModel)) {
      return availableModels;
    }
    return [selectedModel, ...availableModels];
  }, [availableModels, selectedModel]);
  const selectedModelLabel = selectedModel;
  const tokenPercent = getTokenUsagePercent(tokenUsage.used, tokenUsage.capacity);
  const tokenRingColor = tokenPercent >= 90 ? 'hsl(var(--destructive))' : tokenPercent >= 70 ? 'hsl(38 92% 50%)' : 'hsl(142 72% 36%)';
  const tokenUsageTitle = `Token 使用量：${tokenUsage.used.toLocaleString('en-US')} / ${tokenUsage.capacity.toLocaleString('en-US')}`;
  const skillCommand = useMemo(() => findSkillCommand(input, selection.start), [input, selection.start]);
  const skillCommandKey = skillCommand ? `${skillCommand.start}:${skillCommand.end}:${skillCommand.query}` : undefined;
  const skillSuggestions = useMemo(
    () => skillCommand ? filterSkillNames(skills, skillCommand.query) : [],
    [skills, skillCommand],
  );
  const visibleSkillSuggestions = useMemo(() => skillSuggestions.slice(0, 6), [skillSuggestions]);
  const shouldShowSkillMenu = !!skillCommand && visibleSkillSuggestions.length > 0 && dismissedSkillCommandKey !== skillCommandKey;

  useEffect(() => {
    const textarea = textareaRef.current;
    if (!textarea) {
      return;
    }

    textarea.style.height = '0px';
    textarea.style.height = `${Math.min(textarea.scrollHeight, 200)}px`;
  }, [input]);

  useEffect(() => {
    if (dismissedSkillCommandKey && dismissedSkillCommandKey !== skillCommandKey) {
      setDismissedSkillCommandKey(undefined);
    }
  }, [dismissedSkillCommandKey, skillCommandKey]);

  useEffect(() => {
    setActiveSkillIndex(0);
  }, [skillCommandKey]);

  useEffect(() => {
    const pendingSelection = pendingSelectionRef.current;
    const textarea = textareaRef.current;
    if (!pendingSelection || !textarea) {
      return;
    }

    textarea.focus();
    textarea.setSelectionRange(pendingSelection.start, pendingSelection.end);
    setSelection({
      start: pendingSelection.start,
      end: pendingSelection.end,
    });
    pendingSelectionRef.current = undefined;
  }, [input]);

  const applySkill = (skillName: string) => {
    const nextValue = insertSkillCommand(input, selection.start, selection.end, skillName);
    pendingSelectionRef.current = {
      start: nextValue.selectionStart,
      end: nextValue.selectionEnd,
    };
    onInputChange(nextValue.value);
    setDismissedSkillCommandKey(undefined);
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.nativeEvent.isComposing) {
      return;
    }

    if (shouldShowSkillMenu) {
      if (e.key === 'ArrowDown') {
        e.preventDefault();
        setActiveSkillIndex(index => (index + 1) % visibleSkillSuggestions.length);
        return;
      }

      if (e.key === 'ArrowUp') {
        e.preventDefault();
        setActiveSkillIndex(index => (index - 1 + visibleSkillSuggestions.length) % visibleSkillSuggestions.length);
        return;
      }

      if (e.key === 'Escape') {
        e.preventDefault();
        setDismissedSkillCommandKey(skillCommandKey);
        return;
      }

      if (e.key === 'Enter' && !e.shiftKey) {
        e.preventDefault();
        applySkill(visibleSkillSuggestions[activeSkillIndex] ?? visibleSkillSuggestions[0]);
        return;
      }
    }

    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      onSend();
    }
  };

  return (
    <div className="chat-input-top-gap bg-background/95 px-4 pb-4 pt-2.5 backdrop-blur supports-[backdrop-filter]:bg-background/60">
      <div className="chat-input-todo-stack mx-auto flex max-w-3xl flex-col gap-0">
        {shouldShowTodoPanel && (
          <div className="pointer-events-auto">
            <TodoListBlock todoTree={todoTree} isLoading={isLoading} attachedToComposer />
          </div>
        )}

        <div
          className={cn(
            'relative rounded-2xl border bg-background shadow-sm focus-within:ring-1 focus-within:ring-ring transition-all',
          )}
        >
          <Textarea
            ref={textareaRef}
            placeholder="输入消息..."
            className="max-h-[200px] min-h-[96px] resize-none border-0 bg-transparent px-4 py-3 text-base shadow-none focus-visible:ring-0 [scrollbar-width:none] [-ms-overflow-style:none] [&::-webkit-scrollbar]:hidden"
            value={input}
            onChange={e => {
              onInputChange(e.target.value);
              setSelection({
                start: e.target.selectionStart ?? e.target.value.length,
                end: e.target.selectionEnd ?? e.target.value.length,
              });
            }}
            onKeyDown={handleKeyDown}
            onClick={e => {
              setSelection({
                start: e.currentTarget.selectionStart ?? input.length,
                end: e.currentTarget.selectionEnd ?? input.length,
              });
            }}
            onKeyUp={e => {
              setSelection({
                start: e.currentTarget.selectionStart ?? input.length,
                end: e.currentTarget.selectionEnd ?? input.length,
              });
            }}
            onSelect={e => {
              setSelection({
                start: e.currentTarget.selectionStart ?? input.length,
                end: e.currentTarget.selectionEnd ?? input.length,
              });
            }}
            disabled={isLoading}
            rows={1}
          />
          {shouldShowSkillMenu && (
            <div className="px-3 pb-1">
              <div className="rounded-xl border bg-background/95 p-1 shadow-sm">
                {visibleSkillSuggestions.map((skillName, index) => (
                  <button
                    key={skillName}
                    type="button"
                    className={cn(
                      'flex w-full items-center rounded-lg px-3 py-2 text-left text-sm transition-colors',
                      index === activeSkillIndex ? 'bg-accent text-accent-foreground' : 'text-muted-foreground hover:bg-accent/60 hover:text-foreground',
                    )}
                    onMouseDown={event => {
                      event.preventDefault();
                      applySkill(skillName);
                    }}
                  >
                    <span className="font-medium">/{skillName}</span>
                  </button>
                ))}
              </div>
            </div>
          )}
          <div className="flex items-center justify-between px-3 pb-3 pt-1">
            <div className="flex items-center gap-2">
              <DropdownMenu>
                <DropdownMenuTrigger asChild>
                  <Button
                    type="button"
                    variant="ghost"
                    size="sm"
                    className="h-7 rounded-md px-2 text-[11px] text-muted-foreground hover:text-foreground"
                    disabled={modelSelectionDisabled}
                  >
                    <span className="max-w-[120px] truncate">{selectedModelLabel}</span>
                    <ChevronDown className="h-3.5 w-3.5" />
                  </Button>
                </DropdownMenuTrigger>
                <DropdownMenuContent align="start">
                  {modelCandidates.map(model => (
                    <DropdownMenuItem
                      key={model}
                      onClick={() => onModelChange(model)}
                      className="text-xs"
                    >
                      <span className="flex min-w-0 flex-1 items-center">
                        <span className="truncate">{model}</span>
                      </span>
                      {selectedModel === model && <Check className="h-3.5 w-3.5 text-primary" />}
                    </DropdownMenuItem>
                  ))}
                </DropdownMenuContent>
              </DropdownMenu>

              <TooltipProvider delayDuration={120}>
                <Tooltip>
                  <TooltipTrigger asChild>
                    <button
                      type="button"
                      className="inline-flex items-center gap-1 rounded-md px-1 py-0.5 text-[11px] text-muted-foreground hover:text-foreground"
                      aria-label={tokenUsageTitle}
                      title={tokenUsageTitle}
                    >
                      <span
                        className="relative h-4 w-4 rounded-full"
                        style={{
                          background: `conic-gradient(${tokenRingColor} ${tokenPercent * 3.6}deg, hsl(var(--muted)) 0deg)`,
                        }}
                      >
                        <span className="absolute inset-[3px] rounded-full bg-background" />
                      </span>
                      <span>{tokenPercent}%</span>
                    </button>
                  </TooltipTrigger>
                  <TooltipContent side="top" align="start" className="text-[11px]">
                    {tokenUsageTitle}
                  </TooltipContent>
                </Tooltip>
              </TooltipProvider>
            </div>

            <Button
              size="icon"
              className="h-8 w-8 rounded-lg transition-all"
              onClick={onSend}
              disabled={!input.trim() || isLoading}
            >
              <Send className="h-4 w-4" />
            </Button>
          </div>
        </div>
        <div className="text-center text-[10px] text-muted-foreground/60 mt-3 select-none">
          内容由 AI 生成，请仔细甄别
        </div>
      </div>
    </div>
  );
}

