export interface TokenUsageSnapshot {
  inputTokens: number;
  outputTokens: number;
  totalTokens: number;
  promptTokens?: number;
  completionTokens?: number;
  cachedInputTokens?: number;
  reasoningOutputTokens?: number;
}

function asRecord(value: unknown): Record<string, unknown> | undefined {
  return value && typeof value === 'object' ? (value as Record<string, unknown>) : undefined;
}

function asNumber(value: unknown): number | undefined {
  return typeof value === 'number' && Number.isFinite(value) ? value : undefined;
}

function hasAnyNumericKey(record: Record<string, unknown> | undefined, keys: string[]): boolean {
  if (!record) {
    return false;
  }
  return keys.some(key => typeof record[key] === 'number' && Number.isFinite(record[key] as number));
}

export function parseTokenUsageFromAssistantEndData(data: unknown): TokenUsageSnapshot | undefined {
  const eventData = asRecord(data);
  const nestedUsage = asRecord(eventData?.usage);
  const directUsage = hasAnyNumericKey(eventData, ['inputTokens', 'outputTokens', 'totalTokens', 'input_tokens', 'output_tokens', 'total_tokens']) ? eventData : undefined;
  const usage = nestedUsage ?? directUsage;
  if (!usage) {
    return undefined;
  }

  const inputTokens = asNumber(usage.inputTokens) ?? asNumber(usage.input_tokens);
  const outputTokens = asNumber(usage.outputTokens) ?? asNumber(usage.output_tokens);
  const totalTokens =
    asNumber(usage.totalTokens) ??
    asNumber(usage.total_tokens) ??
    (typeof inputTokens === 'number' && typeof outputTokens === 'number' ? inputTokens + outputTokens : undefined);
  if (typeof inputTokens !== 'number' || typeof outputTokens !== 'number' || typeof totalTokens !== 'number') {
    return undefined;
  }

  const promptTokens = asNumber(usage.promptTokens) ?? asNumber(usage.prompt_tokens);
  const completionTokens = asNumber(usage.completionTokens) ?? asNumber(usage.completion_tokens);
  const cachedInputTokens =
    asNumber(usage.cachedInputTokens) ??
    asNumber(usage.cached_input_tokens) ??
    asNumber(usage.prompt_cache_hit_tokens);
  const reasoningOutputTokens =
    asNumber(usage.reasoningOutputTokens) ??
    asNumber(usage.reasoning_output_tokens);

  return {
    inputTokens,
    outputTokens,
    totalTokens,
    ...(typeof promptTokens === 'number' ? { promptTokens } : {}),
    ...(typeof completionTokens === 'number' ? { completionTokens } : {}),
    ...(typeof cachedInputTokens === 'number' ? { cachedInputTokens } : {}),
    ...(typeof reasoningOutputTokens === 'number' ? { reasoningOutputTokens } : {}),
  };
}

export function getTokenUsagePercent(used: number, capacity: number): number {
  if (capacity <= 0) {
    return 0;
  }
  return Math.min(100, Math.max(0, Math.round((used / capacity) * 100)));
}

