import { useState, useRef, useCallback } from 'react';
import { ModelId } from '@/lib/const';
import { Message, TodoTreeItem } from '@/types';
import { TokenUsageSnapshot } from '@/lib/tokenUsage';
import { useConversations } from './useConversations';
import { useModelSelection } from './useModelSelection';
import { useChatHistory } from './useChatHistory';
import { useMessageStream } from './useMessageStream';

interface UseChatOptions {
  onError?: (error: Error) => void;
}

interface UseChatReturn {
  conversations: ReturnType<typeof useConversations>['conversations'];
  messages: Message[];
  todoTree: TodoTreeItem[];
  input: string;
  isLoading: boolean;
  isHistoryLoading: boolean;
  currentId: string | undefined;
  sidebarOpen: boolean;
  availableModels: ModelId[];
  selectedModel: ModelId;
  tokenUsage?: TokenUsageSnapshot;
  modelContextWindows: Partial<Record<ModelId, number>>;
  setInput: (input: string) => void;
  setSidebarOpen: (open: boolean) => void;
  setCurrentId: (id: string | undefined) => void;
  setSelectedModel: (model: ModelId) => void;
  handleSend: () => Promise<void>;
  handleDelete: (id: string) => Promise<void>;
  handleAskUserSubmit: (interruptId: string | undefined, values: string | Record<string, unknown>) => Promise<void>;
  scrollRef: React.RefObject<HTMLDivElement>;
}

export function useChat(options: UseChatOptions = {}): UseChatReturn {
  const [input, setInput] = useState('');
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [currentId, setRawCurrentId] = useState<string | undefined>(undefined);

  const scrollRef = useRef<HTMLDivElement>(null);
  const skipNextHistoryLoadRef = useRef(false);

  const scrollToBottom = useCallback((behavior: ScrollBehavior = 'smooth') => {
    window.setTimeout(() => {
      scrollRef.current?.scrollIntoView({ behavior, block: 'end' });
    }, 50);
  }, []);

  // ── Sub-hooks ────────────────────────────────────────────────────────────────

  const { conversations, loadConversations, handleDelete: _handleDelete } = useConversations({ onError: options.onError });

  const { availableModels, selectedModel, setSelectedModel, modelContextWindows, selectedModelRef } = useModelSelection({
    currentId,
    conversations,
  });

  const {
    messages,
    setMessages,
    todoTree,
    setTodoTree,
    isLoading,
    setIsLoading,
    isHistoryLoading,
    tokenUsage,
    setTokenUsage,
    prepareForSwitch,
  } = useChatHistory({
    currentId,
    skipNextHistoryLoadRef,
    selectedModelRef,
    onScrollToBottom: scrollToBottom,
    onSetSelectedModel: setSelectedModel,
    onError: options.onError,
  });

  const { handleSend, handleAskUserSubmit } = useMessageStream({
    currentId,
    selectedModel,
    messages,
    isLoading,
    input,
    setInput,
    setIsLoading,
    setMessages,
    setTodoTree,
    setTokenUsage,
    setRawCurrentId,
    skipNextHistoryLoadRef,
    onScrollToBottom: scrollToBottom,
    onConversationsRefresh: loadConversations,
    onError: options.onError,
  });

  // ── Conversation switching ───────────────────────────────────────────────────

  const setCurrentId = useCallback((id: string | undefined) => {
    if (id === currentId) return;
    prepareForSwitch(id);
    setRawCurrentId(id);
  }, [currentId, prepareForSwitch]);

  const handleDelete = useCallback(async (id: string) => {
    await _handleDelete(id, currentId, () => setCurrentId(undefined));
  }, [_handleDelete, currentId, setCurrentId]);

  return {
    conversations,
    messages,
    todoTree,
    input,
    isLoading,
    isHistoryLoading,
    currentId,
    sidebarOpen,
    availableModels,
    selectedModel,
    tokenUsage,
    modelContextWindows,
    setInput,
    setSidebarOpen,
    setCurrentId,
    setSelectedModel,
    handleSend,
    handleDelete,
    handleAskUserSubmit,
    scrollRef,
  };
}

