  1→import { AskUserField, AskUserMessage, AskUserPayload, ChatEvent, Message, StreamSource, TodoItem, TodoTreeItem, ToolDetail } from '@/types';
  2→import { parse as parsePartialJson } from 'partial-json';
  3→import {
  4→  buildToolDetailFromArgs,
  5→  formatEventContent,
  6→  generateId,
  7→  getEventContent,
  8→  getToolInputData,
  9→  isDetailToolName,
 10→} from './chatUtils';
 11→import {
 12→  EVENT_USER,
 13→  EVENT_ASSISTANT,
 14→  EVENT_THINKING,
 15→  EVENT_TOOL_INPUT,
 16→  EVENT_TOOL_CALL,
 17→  EVENT_TOOL_CALL_RESULT,
 18→  EVENT_DELIVER,
 19→  EVENT_ERROR,
 20→  EVENT_TOOL_OUTPUT,
 21→  EVENT_INTERRUPT,
 22→  EVENT_SET_ASK_USER,
 23→  EVENT_CONTEXT_SUMMARIZED,
 24→  EVENT_TODO_UPDATE,
 25→  EVENT_AGENT_END,
 26→  EVENT_ASSISTANT_END,
 27→  FILTERED_MESSAGE_EVENTS,
 28→  TOOL_WRITE_TODOS,
 29→  TOOL_ASK_USER,
 30→  TOOL_WRITE_FILE,
 31→  TOOL_EXECUTE,
 32→} from './const';
 33→
 34→// ─── write_todos JSON extraction ─────────────────────────────────────────────
 35→
 36→const VALID_TODO_STATUSES = new Set(['pending', 'in_progress', 'completed']);
 37→
 38→function parseTodoItems(accumulated: string): TodoItem[] {
 39→  try {
 40→    const parsed = parsePartialJson(accumulated);
 41→    return sanitizeTodoItems(parsed?.todos);
 42→  } catch {
 43→    return [];
 44→  }
 45→}
 46→
 47→function sanitizeTodoItems(todos: unknown): TodoItem[] {
 48→  if (!Array.isArray(todos)) {
 49→    return [];
 50→  }
 51→
 52→  return todos.filter(
 53→    (item): item is TodoItem =>
 54→      typeof item?.content === 'string' && VALID_TODO_STATUSES.has(item.status),
 55→  );
 56→}
 57→
 58→function toTodoTree(todos: TodoItem[]): TodoTreeItem[] {
 59→  return todos.map(todo => ({
 60→    ...todo,
 61→    children: [],
 62→  }));
 63→}
 64→
 65→const FILTERED_MESSAGE_EVENT_SET = new Set<string>(FILTERED_MESSAGE_EVENTS);
 66→
 67→function asString(value: unknown): string | undefined {
 68→  return typeof value === 'string' ? value : undefined;
 69→}
 70→
 71→function asNumber(value: unknown): number | undefined {
 72→  return typeof value === 'number' ? value : undefined;
 73→}
 74→
 75→function asBoolean(value: unknown): boolean | undefined {
 76→  return typeof value === 'boolean' ? value : undefined;
 77→}
 78→
 79→function parseAskUserPreview(accumulated: string): AskUserMessage | undefined {
 80→  try {
 81→    const parsed = parsePartialJson(accumulated);
 82→    if (!parsed || typeof parsed !== 'object') return undefined;
 83→
 84→    const data = parsed as Record<string, unknown>;
 85→    const kind = asString(data.kind);
 86→    const agent = asString(data.agent);
 87→
 88→    if (kind === 'chat') {
 89→      const question = asString(data.question) || '';
 90→      if (!question) return undefined;
 91→      return { kind: 'chat', question, agent, isPreview: true, readonly: true };
 92→    }
 93→
 94→    if (kind !== 'form') return undefined;
 95→
 96→    const rawFields = Array.isArray(data.fields) ? data.fields : [];
 97→    const normalizedFields = rawFields
 98→      .map((field, fieldIndex): AskUserField | undefined => {
 99→      if (!field || typeof field !== 'object') return undefined;
100→      const record = field as Record<string, unknown>;
101→      const type = asString(record.type);
102→      const key = asString(record.key) || `preview-field-${fieldIndex}`;
103→      const label = asString(record.label) || key;
104→      const required = asBoolean(record.required);
105→
106→      if (type === 'text') {
107→        return {
108→          type,
109→          key,
110→          label,
111→          required,
112→          placeholder: asString(record.placeholder),
113→          minLength: asNumber(record.minLength),
114→          maxLength: asNumber(record.maxLength),
115→        };
116→      }
117→
118→      if (type === 'number') {
119→        return {
120→          type,
121→          key,
122→          label,
123→          required,
124→          placeholder: asString(record.placeholder),
125→          min: asNumber(record.min),
126→          max: asNumber(record.max),
127→        };
128→      }
129→
130→      if (type === 'radio' || type === 'checkbox') {
131→        const rawOptions = Array.isArray(record.options) ? record.options : [];
132→        const options = rawOptions.flatMap((option, optionIndex) => {
133→          if (!option || typeof option !== 'object') return [];
134→          const optionRecord = option as Record<string, unknown>;
135→          const optionValue = asString(optionRecord.value) || `preview-option-${fieldIndex}-${optionIndex}`;
136→          const optionLabel = asString(optionRecord.label) || optionValue;
137→          return optionLabel || optionValue ? [{ label: optionLabel, value: optionValue }] : [];
138→        });
139→
140→        return {
141→          type,
142→          key,
143→          label,
144→          required,
145→          options,
146→          inspiration: asString(record.inspiration),
147→        };
148→      }
149→
150→      return undefined;
151→    })
152→      .filter((field): field is AskUserField => !!field);
153→
154→    const title = asString(data.title) || '请补充信息';
155→    if (!title && normalizedFields.length === 0) return undefined;
156→    return { kind: 'form', title, fields: normalizedFields, agent, isPreview: true, readonly: true };
157→  } catch {
158→    return undefined;
159→  }
160→}
161→
162→// ─── Processor ────────────────────────────────────────────────────────────────
163→
164→interface ProcessorState {
165→  messages: Message[];
166→  todoTree: TodoTreeItem[];
167→  sourceStates: Record<string, SourceScopedState>;
168→}
169→
170→interface SourceScopedState {
171→  currentAssistantId: string | undefined;
172→  todoMessageId: string | undefined;
173→  todoBuffer: string;
174→  askUserPreviewMessageId: string | undefined;
175→  askUserPreviewBuffer: string;
176→  detailMessageIds: Partial<Record<typeof TOOL_WRITE_FILE | typeof TOOL_EXECUTE, string>>;
177→  detailBuffers: Partial<Record<typeof TOOL_WRITE_FILE | typeof TOOL_EXECUTE, string>>;
178→}
179→
180→/**
181→ * 创建一个有状态的消息处理器。
182→ * 同一套 applyEvent 逻辑被流式处理和历史加载共享，确保两路径产出完全一致的 Message[]。
183→ *
184→ * - 流式：每次 applyEvent 后调用 setMessages([...processor.getMessages()])
185→ * - 历史：批量 applyEvent，最后调用 setMessages(processor.getMessages())
186→ */
187→export function createMessageProcessor(initialMessages: Message[] = []) {
188→  const state: ProcessorState = {
189→    messages: [...initialMessages],
190→    todoTree: [],
191→    sourceStates: {},
192→  };
193→
194→  // ── helpers ──────────────────────────────────────────────────────────────────
195→
196→  function getSourceKey(source?: StreamSource): string {
197→    return source?.key || 'main';
198→  }
199→
200→  function isSameSource(left?: StreamSource, right?: StreamSource): boolean {
201→    return (left?.kind || 'main') === (right?.kind || 'main') && getSourceKey(left) === getSourceKey(right);
202→  }
203→
204→  function resolveEventSource(event: ChatEvent): StreamSource {
205→    if (event.subagentNamespace) {
206→      return {
207→        kind: 'subagent',
208→        key: event.subagentNamespace,
209→        label: event.subagentType,
210→      };
211→    }
212→    return event.source || { kind: 'main', key: 'main', label: event.node };
213→  }
214→
215→  function getSubagentFields(source: StreamSource): Pick<Message, 'subagentType' | 'subagentNamespace'> {
216→    return source.kind === 'subagent'
217→      ? {
218→          subagentType: source.label,
219→          subagentNamespace: source.key,
220→        }
221→      : {
222→          subagentType: undefined,
223→          subagentNamespace: undefined,
224→        };
225→  }
226→
227→  function getSourceState(source: StreamSource): SourceScopedState {
228→    const key = getSourceKey(source);
229→    if (!state.sourceStates[key]) {
230→      state.sourceStates[key] = {
231→        currentAssistantId: undefined,
232→        todoMessageId: undefined,
233→        todoBuffer: '',
234→        askUserPreviewMessageId: undefined,
235→        askUserPreviewBuffer: '',
236→        detailMessageIds: {},
237→        detailBuffers: {},
238→      };
239→    }
240→    return state.sourceStates[key];
241→  }
242→
243→  for (const message of initialMessages) {
244→    const source = message.source || { kind: 'main', key: 'main', label: message.node };
245→    const sourceState = getSourceState(source);
246→    if (message.event === EVENT_TODO_UPDATE) {
247→      sourceState.todoMessageId = message.id;
248→      syncMainTodoTree(source, sanitizeTodoItems(message.todos));
249→    }
250→  }
251→
252→  function push(msg: Omit<Message, 'id'> & { id?: string }): Message {
253→    const m = { ...msg, id: msg.id || generateId() } as Message;
254→    state.messages.push(m);
255→    return m;
256→  }
257→
258→  function updateById(id: string, updater: (msg: Message) => Message): void {
259→    const idx = state.messages.findIndex(m => m.id === id);
260→    if (idx !== -1) state.messages[idx] = updater(state.messages[idx]);
261→  }
262→
263→  function resolveEventId(event: ChatEvent): string {
264→    return event.id || generateId();
265→  }
266→
267→  function resolveEventTimestamp(event: ChatEvent): number {
268→    return typeof event.timestamp === 'number' ? event.timestamp : Date.now();
269→  }
270→
271→  function getToolCallId(data: Record<string, unknown> | undefined): string | undefined {
272→    return typeof data?.id === 'string' ? data.id : undefined;
273→  }
274→
275→  function parseStructuredInput(accumulated: string): Record<string, unknown> | undefined {
276→    if (!accumulated) return undefined;
277→    try {
278→      const parsed = parsePartialJson(accumulated);
279→      return parsed && typeof parsed === 'object' && !Array.isArray(parsed)
280→        ? parsed as Record<string, unknown>
281→        : undefined;
282→    } catch {
283→      return undefined;
284→    }
285→  }
286→
287→  function getMessageById(id: string | undefined): Message | undefined {
288→    if (!id) return undefined;
289→    return state.messages.find(message => message.id === id);
290→  }
291→
292→  // ── ask-user helpers ──────────────────────────────────────────────────────────
293→
294→  function finalizeAskUser(payload: AskUserPayload, event: ChatEvent, sourceState: SourceScopedState, source: StreamSource): void {
295→    const timestamp = resolveEventTimestamp(event);
296→    const content = payload.kind === 'chat' ? payload.question : payload.title;
297→    if (!content) return;
298→
299→    const finalizedPayload: AskUserMessage = {
300→      ...payload,
301→      isPreview: false,
302→      readonly: false,
303→    };
304→
305→    if (sourceState.askUserPreviewMessageId) {
306→      updateById(sourceState.askUserPreviewMessageId, msg => ({
307→        ...msg,
308→        role: 'assistant',
309→        content,
310→        timestamp,
311→        event: EVENT_INTERRUPT,
312→        node: event.node,
313→        askUser: finalizedPayload,
314→        ...getSubagentFields(source),
315→        source,
316→      }));
317→      sourceState.askUserPreviewMessageId = undefined;
318→      sourceState.askUserPreviewBuffer = '';
319→      return;
320→    }
321→
322→    push({
323→      role: 'assistant',
324→      content,
325→      timestamp,
326→      event: EVENT_INTERRUPT,
327→      node: event.node,
328→      askUser: finalizedPayload,
329→      ...getSubagentFields(source),
330→      source,
331→    });
332→    sourceState.askUserPreviewMessageId = undefined;
333→    sourceState.askUserPreviewBuffer = '';
334→  }
335→
336→  function upsertAskUserPreview(payload: AskUserMessage, event: ChatEvent, sourceState: SourceScopedState, source: StreamSource): void {
337→    const timestamp = resolveEventTimestamp(event);
338→    const content = payload.kind === 'chat' ? payload.question : payload.title;
339→    if (payload.kind === 'chat' && !content) return;
340→    if (payload.kind === 'form' && !content && payload.fields.length === 0) return;
341→
342→    if (sourceState.askUserPreviewMessageId) {
343→      updateById(sourceState.askUserPreviewMessageId, msg => ({
344→        ...msg,
345→        role: 'assistant',
346→        content: content || msg.content,
347→        timestamp,
348→        event: EVENT_INTERRUPT,
349→        node: event.node,
350→        askUser: payload,
351→        ...getSubagentFields(source),
352→        source,
353→      }));
354→      return;
355→    }
356→
357→    sourceState.askUserPreviewMessageId = generateId();
358→    push({
359→      id: sourceState.askUserPreviewMessageId,
360→      role: 'assistant',
361→      content: content || '请补充信息',
362→      timestamp,
363→      event: EVENT_INTERRUPT,
364→      node: event.node,
365→      askUser: payload,
366→      ...getSubagentFields(source),
367→      source,
368→    });
369→  }
370→
371→  // ── todo helpers ─────────────────────────────────────────────────────────────
372→
373→  function syncMainTodoTree(source: StreamSource, todos: TodoItem[]): void {
374→    if (source.kind === 'main') {
375→      state.todoTree = toTodoTree(todos);
376→    }
