378→
379→  function createTodoUpdateMessage(
380→    todos: TodoItem[],
381→    event: ChatEvent,
382→    sourceState: SourceScopedState,
383→    source: StreamSource,
384→    timestamp: number,
385→  ): void {
386→    sourceState.todoMessageId = generateId();
387→    syncMainTodoTree(source, todos);
388→    push({
389→      id: sourceState.todoMessageId,
390→      role: 'assistant',
391→      content: '',
392→      timestamp,
393→      event: EVENT_TODO_UPDATE,
394→      node: event.node,
395→      todos,
396→      ...getSubagentFields(source),
397→      source,
398→    });
