401→  function upsertTodo(todos: TodoItem[], event: ChatEvent, sourceState: SourceScopedState, source: StreamSource): void {
402→    const timestamp = resolveEventTimestamp(event);
403→    if (sourceState.todoMessageId) {
404→      updateById(sourceState.todoMessageId, msg => {
405→        const oldTodos = msg.todos || [];
406→        // 流式解析时 partial-json 可能产出 content 为空字符串的不完整条目，
407→        // 只有新条目的 content 非空时才覆盖旧数据，避免已有内容被清空。
408→        const mergedTodos = oldTodos.map((todo, index) => {
409→          const newTodo = todos[index];
410→          return (newTodo?.content) ? newTodo : todo;
411→        });
412→        if (todos.length > oldTodos.length) {
413→          mergedTodos.push(...todos.slice(oldTodos.length).filter(t => t.content));
414→        }
415→        syncMainTodoTree(source, mergedTodos);
416→        return { ...msg, timestamp, todos: mergedTodos };
417→      });
418→    } else {
419→      createTodoUpdateMessage(todos, event, sourceState, source, timestamp);
420→    }
421→  }
422→
423→  function finalizeTodo(todos: TodoItem[], event: ChatEvent, sourceState: SourceScopedState, source: StreamSource): void {
424→    const timestamp = resolveEventTimestamp(event);
425→    if (sourceState.todoMessageId) {
426→      if (todos.length > 0) {
427→        syncMainTodoTree(source, todos);
428→        updateById(sourceState.todoMessageId, msg => ({
429→          ...msg,
430→          timestamp,
431→          todos,
432→          ...getSubagentFields(source),
433→          source,
434→        }));
435→      }
436→      sourceState.todoBuffer = '';
437→    } else if (todos.length > 0) {
438→      createTodoUpdateMessage(todos, event, sourceState, source, timestamp);
439→    }
440→  }
441→
442→  function upsertToolDetailPreview(
443→    toolName: typeof TOOL_WRITE_FILE | typeof TOOL_EXECUTE,
444→    inputText: string,
445→    event: ChatEvent,
446→    sourceState: SourceScopedState,
447→    source: StreamSource,
448→  ): void {
449→    sourceState.currentAssistantId = undefined;
450→    sourceState.detailBuffers[toolName] = (sourceState.detailBuffers[toolName] || '') + (inputText || '');
451→    const parsed = parseStructuredInput(sourceState.detailBuffers[toolName] || '');
452→    if (!parsed) return;
453→
454→    const detail = buildToolDetailFromArgs(toolName, parsed, 'streaming');
455→    if (!detail) return;
456→
457→    const existingId = sourceState.detailMessageIds[toolName];
458→    const timestamp = resolveEventTimestamp(event);
459→    if (existingId) {
460→      updateById(existingId, msg => ({
461→        ...msg,
462→        event: EVENT_TOOL_INPUT,
463→        content: detail.summary,
464→        timestamp,
465→        toolName,
466→        node: event.node,
467→        toolDetail: detail,
468→        ...getSubagentFields(source),
469→        source,
470→      }));
471→      return;
472→    }
473→
474→    const messageId = generateId();
475→    sourceState.detailMessageIds[toolName] = messageId;
476→    push({
477→      id: messageId,
478→      role: 'assistant',
479→      content: detail.summary,
480→      timestamp,
481→      event: EVENT_TOOL_INPUT,
482→      toolName,
483→      node: event.node,
484→      toolDetail: detail,
485→      ...getSubagentFields(source),
486→      source,
487→    });
488→  }
489→
490→  function upsertToolDetailCall(
491→    toolName: typeof TOOL_WRITE_FILE | typeof TOOL_EXECUTE,
492→    data: Record<string, unknown>,
493→    event: ChatEvent,
494→    sourceState: SourceScopedState,
495→    source: StreamSource,
496→  ): void {
497→    const rawInput = typeof data.input === 'string' ? data.input : JSON.stringify(data.input ?? {});
498→    const parsed = parseStructuredInput(rawInput) || parseStructuredInput(sourceState.detailBuffers[toolName] || '');
499→    const previousDetail = getMessageById(sourceState.detailMessageIds[toolName])?.toolDetail;
500→    const detail = parsed
501→      ? buildToolDetailFromArgs(toolName, parsed, 'running')
502→      : previousDetail
503→        ? { ...previousDetail, status: 'running' as const, summary: previousDetail.summary }
504→        : undefined;
505→    if (!detail) return;
506→
507→    const timestamp = resolveEventTimestamp(event);
508→    const toolCallId = getToolCallId(data);
509→    const messageId = sourceState.detailMessageIds[toolName] || generateId();
510→    sourceState.detailMessageIds[toolName] = messageId;
511→    sourceState.detailBuffers[toolName] = '';
512→
513→    const nextDetail: ToolDetail = {
514→      ...detail,
515→      status: 'running',
516→      summary: detail.summary.replace(/ · .+$/, ' · 执行中'),
517→    };
518→
519→    if (getMessageById(messageId)) {
520→      updateById(messageId, msg => ({
521→        ...msg,
522→        event: EVENT_TOOL_CALL,
523→        content: nextDetail.summary,
524→        timestamp,
525→        toolName,
526→        toolCallId,
527→        node: event.node,
528→        toolDetail: nextDetail,
529→        ...getSubagentFields(source),
530→        source,
531→      }));
532→      return;
533→    }
534→
535→    push({
536→      id: messageId,
537→      role: 'assistant',
538→      content: nextDetail.summary,
539→      timestamp,
540→      event: EVENT_TOOL_CALL,
541→      toolName,
542→      toolCallId,
543→      node: event.node,
544→      toolDetail: nextDetail,
545→      ...getSubagentFields(source),
546→      source,
547→    });
548→  }
549→
550→  function finalizeToolDetailResult(
551→    toolName: typeof TOOL_WRITE_FILE | typeof TOOL_EXECUTE,
552→    data: Record<string, unknown>,
553→    event: ChatEvent,
554→    sourceState: SourceScopedState,
555→    source: StreamSource,
556→  ): void {
557→    const messageId = sourceState.detailMessageIds[toolName];
558→    if (!messageId) return;
559→    const existing = getMessageById(messageId);
560→    if (!existing?.toolDetail) return;
561→
562→    const isError = !!data.error;
563→    const output = toolName === TOOL_EXECUTE ? formatEventContent(event) : existing.toolDetail.output;
564→    const nextDetail: ToolDetail = {
565→      ...existing.toolDetail,
566→      status: isError ? 'error' : 'completed',
567→      output,
568→      summary: `${existing.toolDetail.title} · ${isError ? '失败' : '已完成'}`,
569→    };
570→
571→    updateById(messageId, msg => ({
572→      ...msg,
573→      event: EVENT_TOOL_CALL_RESULT,
574→      content: nextDetail.summary,
575→      timestamp: resolveEventTimestamp(event),
576→      toolName,
577→      toolCallId: getToolCallId(data) || msg.toolCallId,
578→      node: event.node,
579→      outputLength: typeof data.outputLength === 'number' ? data.outputLength as number : msg.outputLength,
580→      isError,
581→      toolDetail: nextDetail,
582→      ...getSubagentFields(source),
583→      source,
584→    }));
585→
586→    sourceState.detailMessageIds[toolName] = undefined;
587→    sourceState.detailBuffers[toolName] = '';
588→  }
589→
590→  function pushAssistantMessage(
591→    event: ChatEvent,
592→    source: StreamSource,
593→    content: string,
594→    overrides?: Partial<Message>,
595→  ): void {
596→    push({
597→      id: resolveEventId(event),
598→      role: 'assistant',
599→      content,
600→      timestamp: resolveEventTimestamp(event),
601→      node: event.node,
602→      ...overrides,
603→      ...getSubagentFields(source),
604→      source,
605→    });
606→  }
607→
608→  function handleUserEvent(event: ChatEvent): void {
609→    push({
610→      id: resolveEventId(event),
611→      role: 'user',
612→      content: getEventContent(event),
613→      timestamp: resolveEventTimestamp(event),
614→      event: EVENT_USER,
615→      node: event.node,
616→    });
617→  }
618→
619→  function handleTodoUpdateEvent(event: ChatEvent, sourceState: SourceScopedState, source: StreamSource): void {
620→    const todos = sanitizeTodoItems((event.data as Record<string, unknown>)?.todos);
621→    finalizeTodo(todos, event, sourceState, source);
622→  }
623→
624→  function handleInterruptEvent(event: ChatEvent, sourceState: SourceScopedState, source: StreamSource): void {
625→    const payload = event.data as AskUserPayload | undefined;
626→    if (payload?.kind === 'chat' || payload?.kind === 'form') {
627→      finalizeAskUser(payload, event, sourceState, source);
628→    }
629→  }
630→
631→  function handleSetAskUserEvent(event: ChatEvent): void {
632→    const data = event.data as Record<string, unknown> | undefined;
633→    const interruptId = typeof data?.interruptId === 'string' ? data.interruptId : undefined;
634→    const answer = data?.answer as string | Record<string, unknown> | undefined;
635→    if (!interruptId) return;
636→
637→    for (let i = state.messages.length - 1; i >= 0; i -= 1) {
638→      const msg = state.messages[i];
639→      if (msg.askUser?.interruptId === interruptId) {
640→        state.messages[i] = {
641→          ...msg,
642→          askUser: {
643→            ...msg.askUser,
644→            answer,
645→          } as AskUserMessage,
646→        };
647→        break;
648→      }
649→    }
650→  }
651→
652→  function appendAssistantChunk(
653→    event: ChatEvent,
654→    sourceState: SourceScopedState,
655→    source: StreamSource,
656→    next: { content?: string; thinking?: string },
657→  ): void {
658→    const content = next.content || '';
659→    const thinking = next.thinking || '';
660→
661→    if (sourceState.currentAssistantId) {
662→      updateById(sourceState.currentAssistantId, msg => ({
663→        ...msg,
664→        content: msg.content + content,
665→        thinking: thinking ? (msg.thinking || '') + thinking : msg.thinking,
666→        ...getSubagentFields(source),
667→        source,
668→      }));
669→      return;
670→    }
671→
672→    if (!content && !thinking) {
673→      return;
674→    }
675→
676→    const id = resolveEventId(event);
677→    sourceState.currentAssistantId = id;
678→    push({
679→      id,
680→      role: 'assistant',
681→      content,
682→      thinking: thinking || undefined,
683→      timestamp: resolveEventTimestamp(event),
684→      event: EVENT_ASSISTANT,
685→      node: event.node,
686→      ...getSubagentFields(source),
687→      source,
688→    });
689→  }
690→
691→  function handleAssistantEvent(event: ChatEvent, sourceState: SourceScopedState, source: StreamSource): void {
692→    const content = getEventContent(event);
693→    const thinking = ((event.data as Record<string, unknown>)?.thinking as string) || '';
694→    appendAssistantChunk(event, sourceState, source, { content, thinking });
695→  }
696→
697→  function handleThinkingEvent(event: ChatEvent, sourceState: SourceScopedState, source: StreamSource): void {
698→    const data = event.data as Record<string, unknown>;
699→    const thinkingText = ((data?.thinking as string) || '') + ((data?.content as string) || '');
700→    appendAssistantChunk(event, sourceState, source, { thinking: thinkingText });
701→  }
702→
703→  function handleToolInputEvent(event: ChatEvent, sourceState: SourceScopedState, source: StreamSource): void {
704→    const { toolName, inputText } = getToolInputData(event);
705→
706→    if (toolName === TOOL_ASK_USER) {
707→      sourceState.currentAssistantId = undefined;
708→      sourceState.askUserPreviewBuffer += inputText || '';
709→      const payload = parseAskUserPreview(sourceState.askUserPreviewBuffer);
710→      if (payload) upsertAskUserPreview(payload, event, sourceState, source);
711→      return;
712→    }
713→
714→    if (toolName === TOOL_WRITE_TODOS) {
715→      sourceState.todoBuffer += inputText || '';
716→      const todos = parseTodoItems(sourceState.todoBuffer);
717→      if (todos.length > 0) upsertTodo(todos, event, sourceState, source);
718→      return;
719→    }
720→
721→    if (isDetailToolName(toolName)) {
722→      upsertToolDetailPreview(toolName, inputText, event, sourceState, source);
723→      return;
724→    }
725→
726→    if (!inputText) {
727→      return;
728→    }
729→
730→    const last = state.messages[state.messages.length - 1];
731→    if (
732→      last?.event === EVENT_TOOL_INPUT &&
733→      last.toolName === toolName &&
734→      isSameSource(last.source, source)
735→    ) {
736→      updateById(last.id, msg => ({ ...msg, content: msg.content + inputText }));
737→      return;
738→    }
739→
740→    pushAssistantMessage(event, source, inputText, {
741→      event: EVENT_TOOL_INPUT,
742→      toolName,
743→    });
744→  }
745→
746→  function handleToolCallEvent(event: ChatEvent, sourceState: SourceScopedState, source: StreamSource): void {
747→    const data = event.data as Record<string, unknown>;
748→    const toolName = data?.name as string | undefined;
749→    const toolCallId = getToolCallId(data);
750→
751→    if (toolName === TOOL_WRITE_TODOS) {
752→      const input = typeof data?.input === 'string' ? data.input : JSON.stringify(data?.input ?? {});
753→      const todos = parseTodoItems(input);
754→      finalizeTodo(todos, event, sourceState, source);
755→      return;
756→    }
757→
758→    if (toolName && isDetailToolName(toolName)) {
759→      upsertToolDetailCall(toolName, data, event, sourceState, source);
760→      return;
761→    }
762→
763→    const content = formatEventContent(event);
764→    if (!content) {
765→      return;
766→    }
767→
768→    pushAssistantMessage(event, source, content, {
769→      event: EVENT_TOOL_CALL,
770→      toolName,
771→      toolCallId,
772→    });
773→  }
774→
775→  function handleToolCallResultEvent(event: ChatEvent, sourceState: SourceScopedState, source: StreamSource): void {
776→    const data = event.data as Record<string, unknown>;
777→    const toolName = data?.name as string | undefined;
778→    const toolCallId = getToolCallId(data);
779→    if (toolName === TOOL_WRITE_TODOS) return;
780→
781→    if (toolName && isDetailToolName(toolName)) {
782→      finalizeToolDetailResult(toolName, data, event, sourceState, source);
783→      return;
784→    }
785→
786→    const content = formatEventContent(event);
787→    const outputLength = typeof data?.outputLength === 'number' ? data.outputLength as number : undefined;
788→    const isError = !!data?.error;
789→    if (!content) {
790→      return;
791→    }
792→
793→    pushAssistantMessage(event, source, content, {
794→      event: EVENT_TOOL_CALL_RESULT,
795→      toolName,
796→      toolCallId,
797→      outputLength,
798→      isError,
799→    });
800→  }
801→
802→  function handleDeliverEvent(event: ChatEvent, source: StreamSource): void {
803→    const content = formatEventContent(event);
804→    if (!content) {
805→      return;
806→    }
807→
808→    pushAssistantMessage(event, source, content, {
809→      event: EVENT_DELIVER,
810→    });
811→  }
812→
813→  function handleSimpleAssistantEvent(event: ChatEvent, source: StreamSource): void {
814→    const content = formatEventContent(event);
815→    const data = event.data as Record<string, unknown> | undefined;
816→    const toolName =
817→      event.event === EVENT_ERROR
818→        ? ((data?.toolName as string) || (data?.name as string) || undefined)
819→        : ((data?.name as string) || (data?.agentName as string) || event.node);
820→
821→    pushAssistantMessage(event, source, content, {
822→      event: event.event,
823→      toolName,
824→      isError: event.event === EVENT_ERROR ? true : undefined,
825→    });
826→  }
827→
828→  function applyEvent(event: ChatEvent): void {
829→    const { event: type } = event;
830→    const source = resolveEventSource(event);
831→    const sourceState = getSourceState(source);
832→
833→    // subagent 的 agent-end / assistant-end 推空消息用于 UI 标记结束边界；
834→    // main source 的同类事件在下方的 FILTERED_MESSAGE_EVENT_SET 中被过滤掉。
835→    if ((type === EVENT_AGENT_END || type === EVENT_ASSISTANT_END) && source.kind === 'subagent') {
836→      sourceState.currentAssistantId = undefined;
837→      pushAssistantMessage(event, source, '', {
838→        event: type,
839→      });
840→      return;
841→    }
842→
843→    // 生命周期/控制事件由前端显式过滤，不产出消息（仅对 main source 生效）。
844→    if (FILTERED_MESSAGE_EVENT_SET.has(type)) {
845→      sourceState.currentAssistantId = undefined;
846→      return;
847→    }
848→
849→    // ── 用户消息 ─────────────────────────────────────────────────────────────────
850→    if (type === EVENT_USER) {
851→      sourceState.currentAssistantId = undefined;
852→      handleUserEvent(event);
853→      return;
854→    }
855→
856→    // ── todo-update 自定义事件（on_tool_start 触发，携带完整 todos 数组）────────────
857→    if (type === EVENT_TODO_UPDATE) {
858→      sourceState.currentAssistantId = undefined;
859→      handleTodoUpdateEvent(event, sourceState, source);
860→      return;
861→    }
862→
863→    // ── ask-user 自定义事件（on_tool_start 触发，携带完整 question）──────────────────
864→    if (type === EVENT_INTERRUPT) {
865→      sourceState.currentAssistantId = undefined;
866→      handleInterruptEvent(event, sourceState, source);
867→      return;
868→    }
869→
870→    if (type === EVENT_SET_ASK_USER) {
871→      handleSetAskUserEvent(event);
872→      return;
873→    }
874→
875→    // ── assistant / thinking ──────────────────────────────────────────────────────
876→    if (type === EVENT_ASSISTANT) {
877→      handleAssistantEvent(event, sourceState, source);
878→      return;
879→    }
880→
881→    if (type === EVENT_THINKING) {
882→      handleThinkingEvent(event, sourceState, source);
883→      return;
884→    }
885→
886→    // 非 assistant 事件重置当前 assistant 追踪
887→    sourceState.currentAssistantId = undefined;
888→
889→    // ── context-summarized ───────────────────────────────────────────────────────
890→    if (type === EVENT_CONTEXT_SUMMARIZED) {
891→      const data = event.data as Record<string, unknown> | undefined;
892→      const message = (data?.message as string) || 'Context 已压缩';
893→      pushAssistantMessage(event, source, message, {
894→        event: EVENT_CONTEXT_SUMMARIZED,
895→      });
896→      return;
897→    }
898→
899→    // ── tool-input ────────────────────────────────────────────────────────────────
900→    if (type === EVENT_TOOL_INPUT) {
901→      handleToolInputEvent(event, sourceState, source);
902→      return;
903→    }
904→
905→    // ── tool-call ─────────────────────────────────────────────────────────────────
906→    if (type === EVENT_TOOL_CALL) {
907→      handleToolCallEvent(event, sourceState, source);
908→      return;
909→    }
910→
911→    // ── tool-call-result ──────────────────────────────────────────────────────────
912→    if (type === EVENT_TOOL_CALL_RESULT) {
913→      handleToolCallResultEvent(event, sourceState, source);
914→      return;
915→    }
916→
917→    // ── deliver ───────────────────────────────────────────────────────────────────
918→    if (type === EVENT_DELIVER) {
919→      handleDeliverEvent(event, source);
920→      return;
921→    }
922→
923→    // ── error / tool-output ───────────────────────────────────────────────────────
924→    if (type === EVENT_ERROR || type === EVENT_TOOL_OUTPUT) {
925→      handleSimpleAssistantEvent(event, source);
926→    }
927→  }
928→
929→  return {
930→    applyEvent,
931→    /** 返回当前消息列表的浅拷贝（供 setMessages 使用） */
932→    getMessages: (): Message[] => [...state.messages],
933→    getTodoTree: (): TodoTreeItem[] => [...state.todoTree],
934→  };
935→}
