import { AskUserField, AskUserMessage, AskUserPayload, ChatEvent, Message, StreamSource, TodoItem, TodoTreeItem, ToolDetail } from '@/types';
import { parse as parsePartialJson } from 'partial-json';
import {
  buildToolDetailFromArgs,
  formatEventContent,
  generateId,
  getEventContent,
  getToolInputData,
  isDetailToolName,
} from './chatUtils';
import {
  EVENT_USER,
  EVENT_ASSISTANT,
  EVENT_THINKING,
  EVENT_TOOL_INPUT,
  EVENT_TOOL_CALL,
  EVENT_TOOL_CALL_RESULT,
  EVENT_DELIVER,
  EVENT_ERROR,
  EVENT_TOOL_OUTPUT,
  EVENT_INTERRUPT,
  EVENT_SET_ASK_USER,
  EVENT_CONTEXT_SUMMARIZED,
  EVENT_TODO_UPDATE,
  EVENT_AGENT_END,
  EVENT_ASSISTANT_END,
  FILTERED_MESSAGE_EVENTS,
  TOOL_WRITE_TODOS,
  TOOL_ASK_USER,
  TOOL_WRITE_FILE,
  TOOL_EXECUTE,
} from './const';

// ─── write_todos JSON extraction ─────────────────────────────────────────────

const VALID_TODO_STATUSES = new Set(['pending', 'in_progress', 'completed']);

function parseTodoItems(accumulated: string): TodoItem[] {
  try {
    const parsed = parsePartialJson(accumulated);
    return sanitizeTodoItems(parsed?.todos);
  } catch {
    return [];
  }
}

function sanitizeTodoItems(todos: unknown): TodoItem[] {
  if (!Array.isArray(todos)) {
    return [];
  }

  return todos.filter(
    (item): item is TodoItem =>
      typeof item?.content === 'string' && VALID_TODO_STATUSES.has(item.status),
  );
}

function toTodoTree(todos: TodoItem[]): TodoTreeItem[] {
  return todos.map(todo => ({
    ...todo,
    children: [],
  }));
}

const FILTERED_MESSAGE_EVENT_SET = new Set<string>(FILTERED_MESSAGE_EVENTS);

function asString(value: unknown): string | undefined {
  return typeof value === 'string' ? value : undefined;
}

function asNumber(value: unknown): number | undefined {
  return typeof value === 'number' ? value : undefined;
}

function asBoolean(value: unknown): boolean | undefined {
  return typeof value === 'boolean' ? value : undefined;
}

function parseAskUserPreview(accumulated: string): AskUserMessage | undefined {
  try {
    const parsed = parsePartialJson(accumulated);
    if (!parsed || typeof parsed !== 'object') return undefined;

    const data = parsed as Record<string, unknown>;
    const kind = asString(data.kind);
    const agent = asString(data.agent);

    if (kind === 'chat') {
      const question = asString(data.question) || '';
      if (!question) return undefined;
      return { kind: 'chat', question, agent, isPreview: true, readonly: true };
    }

    if (kind !== 'form') return undefined;

    const rawFields = Array.isArray(data.fields) ? data.fields : [];
    const normalizedFields = rawFields
      .map((field, fieldIndex): AskUserField | undefined => {
      if (!field || typeof field !== 'object') return undefined;
      const record = field as Record<string, unknown>;
      const type = asString(record.type);
      const key = asString(record.key) || `preview-field-${fieldIndex}`;
      const label = asString(record.label) || key;
      const required = asBoolean(record.required);

      if (type === 'text') {
        return {
          type,
          key,
          label,
          required,
          placeholder: asString(record.placeholder),
          minLength: asNumber(record.minLength),
          maxLength: asNumber(record.maxLength),
        };
      }

      if (type === 'number') {
        return {
          type,
          key,
          label,
          required,
          placeholder: asString(record.placeholder),
          min: asNumber(record.min),
          max: asNumber(record.max),
        };
      }

      if (type === 'radio' || type === 'checkbox') {
        const rawOptions = Array.isArray(record.options) ? record.options : [];
        const options = rawOptions.flatMap((option, optionIndex) => {
          if (!option || typeof option !== 'object') return [];
          const optionRecord = option as Record<string, unknown>;
          const optionValue = asString(optionRecord.value) || `preview-option-${fieldIndex}-${optionIndex}`;
          const optionLabel = asString(optionRecord.label) || optionValue;
          return optionLabel || optionValue ? [{ label: optionLabel, value: optionValue }] : [];
        });

        return {
          type,
          key,
          label,
          required,
          options,
          inspiration: asString(record.inspiration),
        };
      }

      return undefined;
    })
      .filter((field): field is AskUserField => !!field);

    const title = asString(data.title) || '请补充信息';
    if (!title && normalizedFields.length === 0) return undefined;
    return { kind: 'form', title, fields: normalizedFields, agent, isPreview: true, readonly: true };
  } catch {
    return undefined;
  }
}

// ─── Processor ────────────────────────────────────────────────────────────────

interface ProcessorState {
  messages: Message[];
  todoTree: TodoTreeItem[];
  sourceStates: Record<string, SourceScopedState>;
}

interface SourceScopedState {
  currentAssistantId: string | undefined;
  todoMessageId: string | undefined;
  todoBuffer: string;
  askUserPreviewMessageId: string | undefined;
  askUserPreviewBuffer: string;
  detailMessageIds: Partial<Record<typeof TOOL_WRITE_FILE | typeof TOOL_EXECUTE, string>>;
  detailBuffers: Partial<Record<typeof TOOL_WRITE_FILE | typeof TOOL_EXECUTE, string>>;
}

/**
 * 创建一个有状态的消息处理器。
 * 同一套 applyEvent 逻辑被流式处理和历史加载共享，确保两路径产出完全一致的 Message[]。
 *
 * - 流式：每次 applyEvent 后调用 setMessages([...processor.getMessages()])
 * - 历史：批量 applyEvent，最后调用 setMessages(processor.getMessages())
 */
export function createMessageProcessor(initialMessages: Message[] = []) {
  const state: ProcessorState = {
    messages: [...initialMessages],
    todoTree: [],
    sourceStates: {},
  };

  // ── helpers ──────────────────────────────────────────────────────────────────

  function getSourceKey(source?: StreamSource): string {
    return source?.key || 'main';
  }

  function isSameSource(left?: StreamSource, right?: StreamSource): boolean {
    return (left?.kind || 'main') === (right?.kind || 'main') && getSourceKey(left) === getSourceKey(right);
  }

  function resolveEventSource(event: ChatEvent): StreamSource {
    if (event.subagentNamespace) {
      return {
        kind: 'subagent',
        key: event.subagentNamespace,
        label: event.subagentType,
      };
    }
    return event.source || { kind: 'main', key: 'main', label: event.node };
  }

  function getSubagentFields(source: StreamSource): Pick<Message, 'subagentType' | 'subagentNamespace'> {
    return source.kind === 'subagent'
      ? {
          subagentType: source.label,
          subagentNamespace: source.key,
        }
      : {
          subagentType: undefined,
          subagentNamespace: undefined,
        };
  }

  function getSourceState(source: StreamSource): SourceScopedState {
    const key = getSourceKey(source);
    if (!state.sourceStates[key]) {
      state.sourceStates[key] = {
        currentAssistantId: undefined,
        todoMessageId: undefined,
        todoBuffer: '',
        askUserPreviewMessageId: undefined,
        askUserPreviewBuffer: '',
        detailMessageIds: {},
        detailBuffers: {},
      };
    }
    return state.sourceStates[key];
  }

  for (const message of initialMessages) {
    const source = message.source || { kind: 'main', key: 'main', label: message.node };
    const sourceState = getSourceState(source);
    if (message.event === EVENT_TODO_UPDATE) {
      sourceState.todoMessageId = message.id;
      syncMainTodoTree(source, sanitizeTodoItems(message.todos));
    }
  }

  function push(msg: Omit<Message, 'id'> & { id?: string }): Message {
    const m = { ...msg, id: msg.id || generateId() } as Message;
    state.messages.push(m);
    return m;
  }

  function updateById(id: string, updater: (msg: Message) => Message): void {
    const idx = state.messages.findIndex(m => m.id === id);
    if (idx !== -1) state.messages[idx] = updater(state.messages[idx]);
  }

  function resolveEventId(event: ChatEvent): string {
    return event.id || generateId();
  }

  function resolveEventTimestamp(event: ChatEvent): number {
    return typeof event.timestamp === 'number' ? event.timestamp : Date.now();
  }

  function getToolCallId(data: Record<string, unknown> | undefined): string | undefined {
    return typeof data?.id === 'string' ? data.id : undefined;
  }

  function parseStructuredInput(accumulated: string): Record<string, unknown> | undefined {
    if (!accumulated) return undefined;
    try {
      const parsed = parsePartialJson(accumulated);
      return parsed && typeof parsed === 'object' && !Array.isArray(parsed)
        ? parsed as Record<string, unknown>
        : undefined;
    } catch {
      return undefined;
    }
  }

  function getMessageById(id: string | undefined): Message | undefined {
    if (!id) return undefined;
    return state.messages.find(message => message.id === id);
  }

  // ── ask-user helpers ──────────────────────────────────────────────────────────

  function finalizeAskUser(payload: AskUserPayload, event: ChatEvent, sourceState: SourceScopedState, source: StreamSource): void {
    const timestamp = resolveEventTimestamp(event);
    const content = payload.kind === 'chat' ? payload.question : payload.title;
    if (!content) return;

    const finalizedPayload: AskUserMessage = {
      ...payload,
      isPreview: false,
      readonly: false,
    };

    if (sourceState.askUserPreviewMessageId) {
      updateById(sourceState.askUserPreviewMessageId, msg => ({
        ...msg,
        role: 'assistant',
        content,
        timestamp,
        event: EVENT_INTERRUPT,
        node: event.node,
        askUser: finalizedPayload,
        ...getSubagentFields(source),
        source,
      }));
      sourceState.askUserPreviewMessageId = undefined;
      sourceState.askUserPreviewBuffer = '';
      return;
    }

    push({
      role: 'assistant',
      content,
      timestamp,
      event: EVENT_INTERRUPT,
      node: event.node,
      askUser: finalizedPayload,
      ...getSubagentFields(source),
      source,
    });
    sourceState.askUserPreviewMessageId = undefined;
    sourceState.askUserPreviewBuffer = '';
  }

  function upsertAskUserPreview(payload: AskUserMessage, event: ChatEvent, sourceState: SourceScopedState, source: StreamSource): void {
    const timestamp = resolveEventTimestamp(event);
    const content = payload.kind === 'chat' ? payload.question : payload.title;
    if (payload.kind === 'chat' && !content) return;
    if (payload.kind === 'form' && !content && payload.fields.length === 0) return;

    if (sourceState.askUserPreviewMessageId) {
      updateById(sourceState.askUserPreviewMessageId, msg => ({
        ...msg,
        role: 'assistant',
        content: content || msg.content,
        timestamp,
        event: EVENT_INTERRUPT,
        node: event.node,
        askUser: payload,
        ...getSubagentFields(source),
        source,
      }));
      return;
    }

    sourceState.askUserPreviewMessageId = generateId();
    push({
      id: sourceState.askUserPreviewMessageId,
      role: 'assistant',
      content: content || '请补充信息',
      timestamp,
      event: EVENT_INTERRUPT,
      node: event.node,
      askUser: payload,
      ...getSubagentFields(source),
      source,
    });
  }

  // ── todo helpers ─────────────────────────────────────────────────────────────

  function syncMainTodoTree(source: StreamSource, todos: TodoItem[]): void {
    if (source.kind === 'main') {
      state.todoTree = toTodoTree(todos);
    }
  }

  function createTodoUpdateMessage(
    todos: TodoItem[],
    event: ChatEvent,
    sourceState: SourceScopedState,
    source: StreamSource,
    timestamp: number,
  ): void {
    sourceState.todoMessageId = generateId();
    syncMainTodoTree(source, todos);
    push({
      id: sourceState.todoMessageId,
      role: 'assistant',
      content: '',
      timestamp,
      event: EVENT_TODO_UPDATE,
      node: event.node,
      todos,
      ...getSubagentFields(source),
      source,
    });
  }

  function upsertTodo(todos: TodoItem[], event: ChatEvent, sourceState: SourceScopedState, source: StreamSource): void {
    const timestamp = resolveEventTimestamp(event);
    if (sourceState.todoMessageId) {
      updateById(sourceState.todoMessageId, msg => {
        const oldTodos = msg.todos || [];
        // 流式解析时 partial-json 可能产出 content 为空字符串的不完整条目，
        // 只有新条目的 content 非空时才覆盖旧数据，避免已有内容被清空。
        const mergedTodos = oldTodos.map((todo, index) => {
          const newTodo = todos[index];
          return (newTodo?.content) ? newTodo : todo;
        });
        if (todos.length > oldTodos.length) {
          mergedTodos.push(...todos.slice(oldTodos.length).filter(t => t.content));
        }
        syncMainTodoTree(source, mergedTodos);
        return { ...msg, timestamp, todos: mergedTodos };
      });
    } else {
      createTodoUpdateMessage(todos, event, sourceState, source, timestamp);
    }
  }

  function finalizeTodo(todos: TodoItem[], event: ChatEvent, sourceState: SourceScopedState, source: StreamSource): void {
    const timestamp = resolveEventTimestamp(event);
    if (sourceState.todoMessageId) {
      if (todos.length > 0) {
        syncMainTodoTree(source, todos);
        updateById(sourceState.todoMessageId, msg => ({
          ...msg,
          timestamp,
          todos,
          ...getSubagentFields(source),
          source,
        }));
      }
      sourceState.todoBuffer = '';
    } else if (todos.length > 0) {
      createTodoUpdateMessage(todos, event, sourceState, source, timestamp);
    }
  }

  function upsertToolDetailPreview(
    toolName: typeof TOOL_WRITE_FILE | typeof TOOL_EXECUTE,
    inputText: string,
    event: ChatEvent,
    sourceState: SourceScopedState,
    source: StreamSource,
  ): void {
    sourceState.currentAssistantId = undefined;
    sourceState.detailBuffers[toolName] = (sourceState.detailBuffers[toolName] || '') + (inputText || '');
    const parsed = parseStructuredInput(sourceState.detailBuffers[toolName] || '');
    if (!parsed) return;

    const detail = buildToolDetailFromArgs(toolName, parsed, 'streaming');
    if (!detail) return;

    const existingId = sourceState.detailMessageIds[toolName];
    const timestamp = resolveEventTimestamp(event);
    if (existingId) {
      updateById(existingId, msg => ({
        ...msg,
        event: EVENT_TOOL_INPUT,
        content: detail.summary,
        timestamp,
        toolName,
        node: event.node,
        toolDetail: detail,
        ...getSubagentFields(source),
        source,
      }));
      return;
    }

    const messageId = generateId();
    sourceState.detailMessageIds[toolName] = messageId;
    push({
      id: messageId,
      role: 'assistant',
      content: detail.summary,
      timestamp,
      event: EVENT_TOOL_INPUT,
      toolName,
      node: event.node,
      toolDetail: detail,
      ...getSubagentFields(source),
      source,
    });
  }

  function upsertToolDetailCall(
    toolName: typeof TOOL_WRITE_FILE | typeof TOOL_EXECUTE,
    data: Record<string, unknown>,
    event: ChatEvent,
    sourceState: SourceScopedState,
    source: StreamSource,
  ): void {
    const rawInput = typeof data.input === 'string' ? data.input : JSON.stringify(data.input ?? {});
    const parsed = parseStructuredInput(rawInput) || parseStructuredInput(sourceState.detailBuffers[toolName] || '');
    const previousDetail = getMessageById(sourceState.detailMessageIds[toolName])?.toolDetail;
    const detail = parsed
      ? buildToolDetailFromArgs(toolName, parsed, 'running')
      : previousDetail
        ? { ...previousDetail, status: 'running' as const, summary: previousDetail.summary }
        : undefined;
    if (!detail) return;

    const timestamp = resolveEventTimestamp(event);
    const toolCallId = getToolCallId(data);
    const messageId = sourceState.detailMessageIds[toolName] || generateId();
    sourceState.detailMessageIds[toolName] = messageId;
    sourceState.detailBuffers[toolName] = '';

    const nextDetail: ToolDetail = {
      ...detail,
      status: 'running',
      summary: detail.summary.replace(/ · .+$/, ' · 执行中'),
    };

    if (getMessageById(messageId)) {
      updateById(messageId, msg => ({
        ...msg,
        event: EVENT_TOOL_CALL,
        content: nextDetail.summary,
        timestamp,
        toolName,
        toolCallId,
        node: event.node,
        toolDetail: nextDetail,
        ...getSubagentFields(source),
        source,
      }));
      return;
    }

    push({
      id: messageId,
      role: 'assistant',
      content: nextDetail.summary,
      timestamp,
      event: EVENT_TOOL_CALL,
      toolName,
      toolCallId,
      node: event.node,
      toolDetail: nextDetail,
      ...getSubagentFields(source),
      source,
    });
  }

  function finalizeToolDetailResult(
    toolName: typeof TOOL_WRITE_FILE | typeof TOOL_EXECUTE,
    data: Record<string, unknown>,
    event: ChatEvent,
    sourceState: SourceScopedState,
    source: StreamSource,
  ): void {
    const messageId = sourceState.detailMessageIds[toolName];
    if (!messageId) return;
    const existing = getMessageById(messageId);
    if (!existing?.toolDetail) return;

    const isError = !!data.error;
    const output = toolName === TOOL_EXECUTE ? formatEventContent(event) : existing.toolDetail.output;
    const nextDetail: ToolDetail = {
      ...existing.toolDetail,
      status: isError ? 'error' : 'completed',
      output,
      summary: `${existing.toolDetail.title} · ${isError ? '失败' : '已完成'}`,
    };

    updateById(messageId, msg => ({
      ...msg,
      event: EVENT_TOOL_CALL_RESULT,
      content: nextDetail.summary,
      timestamp: resolveEventTimestamp(event),
      toolName,
      toolCallId: getToolCallId(data) || msg.toolCallId,
      node: event.node,
      outputLength: typeof data.outputLength === 'number' ? data.outputLength as number : msg.outputLength,
      isError,
      toolDetail: nextDetail,
      ...getSubagentFields(source),
      source,
    }));

    sourceState.detailMessageIds[toolName] = undefined;
    sourceState.detailBuffers[toolName] = '';
  }

  function pushAssistantMessage(
    event: ChatEvent,
    source: StreamSource,
    content: string,
    overrides?: Partial<Message>,
  ): void {
    push({
      id: resolveEventId(event),
      role: 'assistant',
      content,
      timestamp: resolveEventTimestamp(event),
      node: event.node,
      ...overrides,
      ...getSubagentFields(source),
      source,
    });
  }

  function handleUserEvent(event: ChatEvent): void {
    push({
      id: resolveEventId(event),
      role: 'user',
      content: getEventContent(event),
      timestamp: resolveEventTimestamp(event),
      event: EVENT_USER,
      node: event.node,
    });
  }

  function handleTodoUpdateEvent(event: ChatEvent, sourceState: SourceScopedState, source: StreamSource): void {
    const todos = sanitizeTodoItems((event.data as Record<string, unknown>)?.todos);
    finalizeTodo(todos, event, sourceState, source);
  }

  function handleInterruptEvent(event: ChatEvent, sourceState: SourceScopedState, source: StreamSource): void {
    const payload = event.data as AskUserPayload | undefined;
    if (payload?.kind === 'chat' || payload?.kind === 'form') {
      finalizeAskUser(payload, event, sourceState, source);
    }
  }

  function handleSetAskUserEvent(event: ChatEvent): void {
    const data = event.data as Record<string, unknown> | undefined;
    const interruptId = typeof data?.interruptId === 'string' ? data.interruptId : undefined;
    const answer = data?.answer as string | Record<string, unknown> | undefined;
    if (!interruptId) return;

    for (let i = state.messages.length - 1; i >= 0; i -= 1) {
      const msg = state.messages[i];
      if (msg.askUser?.interruptId === interruptId) {
        state.messages[i] = {
          ...msg,
          askUser: {
            ...msg.askUser,
            answer,
          } as AskUserMessage,
        };
        break;
      }
    }
  }

  function appendAssistantChunk(
    event: ChatEvent,
    sourceState: SourceScopedState,
    source: StreamSource,
    next: { content?: string; thinking?: string },
  ): void {
    const content = next.content || '';
    const thinking = next.thinking || '';

    if (sourceState.currentAssistantId) {
      updateById(sourceState.currentAssistantId, msg => ({
        ...msg,
        content: msg.content + content,
        thinking: thinking ? (msg.thinking || '') + thinking : msg.thinking,
        ...getSubagentFields(source),
        source,
      }));
      return;
    }

    if (!content && !thinking) {
      return;
    }

    const id = resolveEventId(event);
    sourceState.currentAssistantId = id;
    push({
      id,
      role: 'assistant',
      content,
      thinking: thinking || undefined,
      timestamp: resolveEventTimestamp(event),
      event: EVENT_ASSISTANT,
      node: event.node,
      ...getSubagentFields(source),
      source,
    });
  }

  function handleAssistantEvent(event: ChatEvent, sourceState: SourceScopedState, source: StreamSource): void {
    const content = getEventContent(event);
    const thinking = ((event.data as Record<string, unknown>)?.thinking as string) || '';
    appendAssistantChunk(event, sourceState, source, { content, thinking });
  }

  function handleThinkingEvent(event: ChatEvent, sourceState: SourceScopedState, source: StreamSource): void {
    const data = event.data as Record<string, unknown>;
    const thinkingText = ((data?.thinking as string) || '') + ((data?.content as string) || '');
    appendAssistantChunk(event, sourceState, source, { thinking: thinkingText });
  }

  function handleToolInputEvent(event: ChatEvent, sourceState: SourceScopedState, source: StreamSource): void {
    const { toolName, inputText } = getToolInputData(event);

    if (toolName === TOOL_ASK_USER) {
      sourceState.currentAssistantId = undefined;
      sourceState.askUserPreviewBuffer += inputText || '';
      const payload = parseAskUserPreview(sourceState.askUserPreviewBuffer);
      if (payload) upsertAskUserPreview(payload, event, sourceState, source);
      return;
    }

    if (toolName === TOOL_WRITE_TODOS) {
      sourceState.todoBuffer += inputText || '';
      const todos = parseTodoItems(sourceState.todoBuffer);
      if (todos.length > 0) upsertTodo(todos, event, sourceState, source);
      return;
    }

    if (isDetailToolName(toolName)) {
      upsertToolDetailPreview(toolName, inputText, event, sourceState, source);
      return;
    }

    if (!inputText) {
      return;
    }

    const last = state.messages[state.messages.length - 1];
    if (
      last?.event === EVENT_TOOL_INPUT &&
      last.toolName === toolName &&
      isSameSource(last.source, source)
    ) {
      updateById(last.id, msg => ({ ...msg, content: msg.content + inputText }));
      return;
    }

    pushAssistantMessage(event, source, inputText, {
      event: EVENT_TOOL_INPUT,
      toolName,
    });
  }

  function handleToolCallEvent(event: ChatEvent, sourceState: SourceScopedState, source: StreamSource): void {
    const data = event.data as Record<string, unknown>;
    const toolName = data?.name as string | undefined;
    const toolCallId = getToolCallId(data);

    if (toolName === TOOL_WRITE_TODOS) {
      const input = typeof data?.input === 'string' ? data.input : JSON.stringify(data?.input ?? {});
      const todos = parseTodoItems(input);
      finalizeTodo(todos, event, sourceState, source);
      return;
    }

    if (toolName && isDetailToolName(toolName)) {
      upsertToolDetailCall(toolName, data, event, sourceState, source);
      return;
    }

    const content = formatEventContent(event);
    if (!content) {
      return;
    }

    pushAssistantMessage(event, source, content, {
      event: EVENT_TOOL_CALL,
      toolName,
      toolCallId,
    });
  }

  function handleToolCallResultEvent(event: ChatEvent, sourceState: SourceScopedState, source: StreamSource): void {
    const data = event.data as Record<string, unknown>;
    const toolName = data?.name as string | undefined;
    const toolCallId = getToolCallId(data);
    if (toolName === TOOL_WRITE_TODOS) return;

    if (toolName && isDetailToolName(toolName)) {
      finalizeToolDetailResult(toolName, data, event, sourceState, source);
      return;
    }

    const content = formatEventContent(event);
    const outputLength = typeof data?.outputLength === 'number' ? data.outputLength as number : undefined;
    const isError = !!data?.error;
    if (!content) {
      return;
    }

    pushAssistantMessage(event, source, content, {
      event: EVENT_TOOL_CALL_RESULT,
      toolName,
      toolCallId,
      outputLength,
      isError,
    });
  }

  function handleDeliverEvent(event: ChatEvent, source: StreamSource): void {
    const content = formatEventContent(event);
    if (!content) {
      return;
    }

    pushAssistantMessage(event, source, content, {
      event: EVENT_DELIVER,
    });
  }

  function handleSimpleAssistantEvent(event: ChatEvent, source: StreamSource): void {
    const content = formatEventContent(event);
    const data = event.data as Record<string, unknown> | undefined;
    const toolName =
      event.event === EVENT_ERROR
        ? ((data?.toolName as string) || (data?.name as string) || undefined)
        : ((data?.name as string) || (data?.agentName as string) || event.node);

    pushAssistantMessage(event, source, content, {
      event: event.event,
      toolName,
      isError: event.event === EVENT_ERROR ? true : undefined,
    });
  }

  function applyEvent(event: ChatEvent): void {
    const { event: type } = event;
    const source = resolveEventSource(event);
    const sourceState = getSourceState(source);

    // subagent 的 agent-end / assistant-end 推空消息用于 UI 标记结束边界；
    // main source 的同类事件在下方的 FILTERED_MESSAGE_EVENT_SET 中被过滤掉。
    if ((type === EVENT_AGENT_END || type === EVENT_ASSISTANT_END) && source.kind === 'subagent') {
      sourceState.currentAssistantId = undefined;
      pushAssistantMessage(event, source, '', {
        event: type,
      });
      return;
    }

    // 生命周期/控制事件由前端显式过滤，不产出消息（仅对 main source 生效）。
    if (FILTERED_MESSAGE_EVENT_SET.has(type)) {
      sourceState.currentAssistantId = undefined;
      return;
    }

    // ── 用户消息 ─────────────────────────────────────────────────────────────────
    if (type === EVENT_USER) {
      sourceState.currentAssistantId = undefined;
      handleUserEvent(event);
      return;
    }

    // ── todo-update 自定义事件（on_tool_start 触发，携带完整 todos 数组）────────────
    if (type === EVENT_TODO_UPDATE) {
      sourceState.currentAssistantId = undefined;
      handleTodoUpdateEvent(event, sourceState, source);
      return;
    }

    // ── ask-user 自定义事件（on_tool_start 触发，携带完整 question）──────────────────
    if (type === EVENT_INTERRUPT) {
      sourceState.currentAssistantId = undefined;
      handleInterruptEvent(event, sourceState, source);
      return;
    }

    if (type === EVENT_SET_ASK_USER) {
      handleSetAskUserEvent(event);
      return;
    }

    // ── assistant / thinking ──────────────────────────────────────────────────────
    if (type === EVENT_ASSISTANT) {
      handleAssistantEvent(event, sourceState, source);
      return;
    }

    if (type === EVENT_THINKING) {
      handleThinkingEvent(event, sourceState, source);
      return;
    }

    // 非 assistant 事件重置当前 assistant 追踪
    sourceState.currentAssistantId = undefined;

    // ── context-summarized ───────────────────────────────────────────────────────
    if (type === EVENT_CONTEXT_SUMMARIZED) {
      const data = event.data as Record<string, unknown> | undefined;
      const message = (data?.message as string) || 'Context 已压缩';
      pushAssistantMessage(event, source, message, {
        event: EVENT_CONTEXT_SUMMARIZED,
      });
      return;
    }

    // ── tool-input ────────────────────────────────────────────────────────────────
    if (type === EVENT_TOOL_INPUT) {
      handleToolInputEvent(event, sourceState, source);
      return;
    }

    // ── tool-call ─────────────────────────────────────────────────────────────────
    if (type === EVENT_TOOL_CALL) {
      handleToolCallEvent(event, sourceState, source);
      return;
    }

    // ── tool-call-result ──────────────────────────────────────────────────────────
    if (type === EVENT_TOOL_CALL_RESULT) {
      handleToolCallResultEvent(event, sourceState, source);
      return;
    }

    // ── deliver ───────────────────────────────────────────────────────────────────
    if (type === EVENT_DELIVER) {
      handleDeliverEvent(event, source);
      return;
    }

    // ── error / tool-output ───────────────────────────────────────────────────────
    if (type === EVENT_ERROR || type === EVENT_TOOL_OUTPUT) {
      handleSimpleAssistantEvent(event, source);
    }
  }

  return {
    applyEvent,
    /** 返回当前消息列表的浅拷贝（供 setMessages 使用） */
    getMessages: (): Message[] => [...state.messages],
    getTodoTree: (): TodoTreeItem[] => [...state.todoTree],
  };
}

