import { useState, useEffect, useRef, useCallback } from 'react';
import { Message, ChatEvent, TodoTreeItem } from '@/types';
import { getChatHistory, getConversationStatus } from '@/lib/api';
import { createMessageProcessor } from '@/lib/messageProcessor';
import { parseTokenUsageFromAssistantEndData, type TokenUsageSnapshot } from '@/lib/tokenUsage';
import { EVENT_ASSISTANT_END, ModelId } from '@/lib/const';

interface UseChatHistoryOptions {
  currentId: string | undefined;
  skipNextHistoryLoadRef: React.MutableRefObject<boolean>;
  selectedModelRef: React.MutableRefObject<ModelId>;
  onScrollToBottom: (behavior?: ScrollBehavior) => void;
  onSetSelectedModel: (model: ModelId) => void;
  onError?: (error: Error) => void;
}

export function useChatHistory({
  currentId,
  skipNextHistoryLoadRef,
  selectedModelRef,
  onScrollToBottom,
  onSetSelectedModel,
  onError,
}: UseChatHistoryOptions) {
  const [messages, setMessages] = useState<Message[]>([]);
  const [todoTree, setTodoTree] = useState<TodoTreeItem[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isHistoryLoading, setIsHistoryLoading] = useState(false);
  const [tokenUsage, setTokenUsage] = useState<TokenUsageSnapshot | undefined>(undefined);
  const onErrorRef = useRef(onError);
  onErrorRef.current = onError;

  // Sync conversation status (model + tokenUsage) when switching conversations
  useEffect(() => {
    let cancelled = false;
    if (!currentId) return () => { cancelled = true; };

    void (async () => {
      try {
        const status = await getConversationStatus(currentId);
        if (cancelled || !status) return;

        const modelFromStatus = status.model as ModelId | undefined;
        if (modelFromStatus && modelFromStatus !== selectedModelRef.current) {
          onSetSelectedModel(modelFromStatus);
        }

        if (status.tokenUsage) {
          setTokenUsage(status.tokenUsage);
        }
      } catch (error) {
        console.error('Failed to load conversation status', error);
